-- Schema for Domain: content | Business: Sports Entertainment | Version: v1_mvm
-- Generated on: 2026-05-09 04:52:09

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`content` COMMENT 'Digital asset management domain owning video highlights, photography, social media assets, user-generated content (UGC), audio, and editorial content managed through Dalet Galaxy DAM. Manages content production workflows, metadata tagging, rights clearance (DRM), and CDN distribution for OTT, digital platforms, and social channels. SSOT for all content asset identity and rights metadata.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`asset` (
    `asset_id` BIGINT COMMENT 'Unique surrogate identifier for each digital content asset record in the Dalet Galaxy DAM system. Primary key for the asset master entity.',
    `athlete_profile_id` BIGINT COMMENT 'Reference to the primary athlete featured in this asset. Used for NIL (Name, Image, and Likeness) rights tracking, athlete profile content aggregation, and personalised fan experience delivery via Adobe Experience Platform.',
    `asset_athlete_profile_id` BIGINT COMMENT 'Reference to the primary athlete featured in this asset. Used for NIL (Name, Image, and Likeness) rights tracking, athlete profile content aggregation, and personalised fan experience delivery via Adobe Experience Platform.',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event (match, game, concert, tournament) that this asset is associated with. Enables event-centric content aggregation, broadcast rights enforcement, and fan engagement analytics.',
    `asset_fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event (match, game, concert, tournament) that this asset is associated with. Enables event-centric content aggregation, broadcast rights enforcement, and fan engagement analytics.',
    `category_id` BIGINT COMMENT 'Foreign key linking to content.content_category. Business justification: Assets belong to content categories for taxonomy and rights management. Currently has content_category STRING which should be normalized to content_category.content_category_id FK. Content_category ta',
    `competition_round_id` BIGINT COMMENT 'Foreign key linking to event.competition_round. Business justification: Round draw graphics, round preview videos, and round summary assets are produced and archived at the competition round level for rights management and archive retrieval. asset has fixture_id but no ro',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Assets containing personal data (athlete footage, UGC, biometric overlays) must reference the GDPR/CCPA data processing record governing their retention and usage rights. Content rights managers query',
    `draft_id` BIGINT COMMENT 'Foreign key linking to league.draft. Business justification: Draft-day content (pick announcement footage, war-room clips, prospect profiles) is a major annual content production event. Assets are cataloged against the specific draft for rights management, spon',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Content assets produced by or featuring a specific franchise (team highlight reels, franchise media) require franchise attribution for rights ownership and team-branded asset management. Essential for',
    `game_result_id` BIGINT COMMENT 'Foreign key linking to league.game_result. Business justification: Post-game highlight production, clip libraries, and broadcast packages are directly tied to specific game results. Content operations teams pull game_result metadata (score, OT, attendance) to tag and',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Assets are governed by content policies (broadcast standards, UGC policy, watermarking policy). Rights managers and compliance officers need to identify which policy governs an assets permitted use, ',
    `investigation_id` BIGINT COMMENT 'Foreign key linking to compliance.investigation. Business justification: Assets subject to compliance investigations (copyright infringement, NIL violation, broadcast rights misuse) must be linked to the investigation record. Compliance investigators and legal teams need t',
    `match_result_id` BIGINT COMMENT 'Foreign key linking to event.match_result. Business justification: Post-match highlight assets, official result graphics, and match report videos are produced against the confirmed match result record for rights compliance and archive retrieval. asset has fixture_id ',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Every content asset is governed by a media rights deal defining its distribution rights, territory exclusivity, and expiry. Rights clearance and compliance teams must know which deal covers each asset',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: NIL rights governance: content assets produced under athlete NIL agreements must reference the governing deal for usage rights validation, territory compliance, and platform-scope enforcement. Sports-',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff bracket graphics, preview packages, and round-by-round highlight reels are produced and rights-cleared against specific playoff brackets. Bracket-scoped asset management drives OTT packaging a',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped asset cataloging is core to DAM and rights management — broadcast archives, season recap reels, and licensed highlight packages are organized and rights-cleared per league season. A spor',
    `sponsor_id` BIGINT COMMENT 'Foreign key linking to sponsorship.sponsor. Business justification: Brand safety and rights clearance workflows require knowing which sponsor owns or commissioned a content asset. DAM systems in sports entertainment tag assets by sponsor for exclusivity enforcement, b',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where the content was captured. Supports venue-specific content cataloguing, location-based fan engagement, and venue operations reporting.',
    `aspect_ratio` STRING COMMENT 'Display aspect ratio of the video or image asset. Drives platform-specific rendering and social media format compliance (e.g., 9:16 for vertical social stories, 16:9 for broadcast and OTT, 1:1 for social feed posts).. Valid values are `16:9|4:3|1:1|9:16|21:9`',
    `asset_description` STRING COMMENT 'Free-text editorial description of the asset content, providing context for search, discovery, and editorial use. Includes scene description, key subjects, and contextual notes as entered by the content team in Dalet Galaxy.',
    `asset_type` STRING COMMENT 'Primary classification of the digital content asset format managed in the DAM. Drives workflow routing, rights clearance rules, and CDN distribution logic. [ENUM-REF-CANDIDATE: video|photo|audio|editorial|social_media|ugc|graphic|document — promote to reference product if additional types are required]. Valid values are `video|photo|audio|editorial|social_media|ugc`',
    `bitrate_kbps` STRING COMMENT 'Encoding bitrate of the media asset in kilobits per second. Used for CDN bandwidth planning, OTT adaptive bitrate ladder configuration, and broadcast transmission quality assessment.',
    `broadcast_channel` STRING COMMENT 'Name or identifier of the broadcast or OTT channel for which this asset was primarily produced or first aired (e.g., ESPN, TNT, NBC Sports, league OTT platform). Used for broadcast rights attribution and RSN (Regional Sports Network) distribution tracking.',
    `cdn_url` STRING COMMENT 'Primary CDN (Content Delivery Network) delivery URL for the published asset. Used by OTT platforms, digital channels, and social media integrations to stream or download the asset. Null if the asset has not been published to CDN.. Valid values are `^https?://.+`',
    `codec` STRING COMMENT 'Video or audio codec used to encode the media file (e.g., H.264, H.265/HEVC, ProRes, DNxHD, AAC, PCM). Determines transcoding requirements, CDN compatibility, and broadcast delivery specifications.',
    `content_rating` STRING COMMENT 'Audience content rating classification assigned to the asset per broadcast and streaming standards (e.g., TV-G, TV-PG, TV-14, TV-MA for television; G, PG, PG-13, R for film-style content). Enforced at OTT platform and broadcast distribution layer for audience protection compliance. [ENUM-REF-CANDIDATE: G|PG|PG-13|R|NC-17|TV-G|TV-PG|TV-14|TV-MA — 9 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the asset record was first created in the DAM master catalogue. Distinct from ingest_timestamp which reflects the media file arrival; this reflects the metadata record creation event.',
    `dam_asset_reference` STRING COMMENT 'Native asset identifier assigned by Dalet Galaxy DAM system. Used for cross-system reconciliation and direct lookup within the DAM platform.',
    `drm_status` STRING COMMENT 'Current rights clearance status of the asset under the DRM framework. Controls whether the asset can be distributed via OTT, broadcast, or social channels. Cleared = fully rights-cleared for distribution; Embargoed = time-restricted; Expired = rights window has lapsed.. Valid values are `cleared|pending|restricted|embargoed|expired`',
    `duration_seconds` STRING COMMENT 'Playback duration of the media asset in seconds. Applicable to video and audio asset types. Used for broadcast scheduling, OTT player configuration, and content performance analytics. Null for non-temporal asset types such as photography or editorial.',
    `file_format` STRING COMMENT 'Technical file format or container format of the primary media file (e.g., MP4, MXF for broadcast video, WAV for audio, JPEG/PNG for photography). Drives transcoding workflow selection and CDN delivery profile assignment. [ENUM-REF-CANDIDATE: MP4|MOV|MXF|WAV|MP3|JPEG|PNG|PDF|XML|JSON — 10 candidates stripped; promote to reference product]',
    `file_name` STRING COMMENT 'Original file name of the primary media file as ingested into Dalet Galaxy DAM. Used for file-level traceability, deduplication checks, and storage management.',
    `file_size_bytes` BIGINT COMMENT 'Size of the primary media file in bytes as stored in Dalet Galaxy DAM. Used for storage capacity planning, CDN bandwidth estimation, and ingest SLA monitoring.',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate in frames per second (fps) for video assets (e.g., 23.98, 25.00, 29.97, 50.00, 59.94). Critical for broadcast compliance, transcoding workflow selection, and OTT adaptive bitrate streaming configuration.',
    `ingest_source` STRING COMMENT 'Origin channel through which the asset was ingested into Dalet Galaxy DAM. Supports provenance tracking, quality control routing, and UGC (User-Generated Content) compliance workflows. OB refers to Outside Broadcast feed.. Valid values are `dam_upload|ob_feed|api_ingest|ugc_platform|social_import|manual_entry`',
    `ingest_timestamp` TIMESTAMP COMMENT 'Date and time when the asset was first ingested into the Dalet Galaxy DAM system. Used for SLA tracking, content freshness reporting, and audit trail compliance.',
    `is_live_clip` BOOLEAN COMMENT 'Indicates whether this asset was captured or clipped from a live broadcast event (e.g., live match highlight, live concert clip). Drives near-real-time CDN distribution workflows and live rights clearance checks.',
    `is_ppv_restricted` BOOLEAN COMMENT 'Indicates whether this asset is associated with a Pay-Per-View (PPV) event and subject to PPV access restrictions. When true, distribution is gated behind PPV entitlement checks at the OTT and digital platform layer.',
    `is_ugc` BOOLEAN COMMENT 'Indicates whether this asset was submitted as User-Generated Content (UGC) by a fan or external contributor rather than produced by the organisations internal content team. UGC assets require additional rights clearance and moderation workflows.',
    `language_code` STRING COMMENT 'Primary language of the asset content expressed as an IETF BCP 47 language tag (e.g., en, en-US, es, fr, pt-BR). Used for localisation routing, subtitle matching, and regional distribution targeting.. Valid values are `^[a-z]{2,3}(-[A-Z]{2,3})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when the asset record was most recently updated in the DAM. Supports change detection, incremental ETL processing, and editorial audit trails.',
    `lifecycle_status` STRING COMMENT 'Current state of the asset within the content production and distribution lifecycle managed in Dalet Galaxy. Controls editorial workflow progression, rights enforcement, and CDN availability. [ENUM-REF-CANDIDATE: draft|ingest|review|approved|published|archived|deleted|quarantined — promote to reference product if additional states are required]',
    `published_timestamp` TIMESTAMP COMMENT 'Date and time when the asset was first published and made available for distribution via CDN to OTT, digital, or social platforms. Null if the asset has not yet been published.',
    `resolution` STRING COMMENT 'Video or image resolution classification of the asset (SD=Standard Definition, HD=High Definition 720p, FHD=Full HD 1080p, 4K=Ultra HD, 8K=Super Hi-Vision). Determines CDN delivery tier, OTT streaming profile, and broadcast transmission specification.. Valid values are `SD|HD|FHD|4K|8K`',
    `rights_owner` STRING COMMENT 'Name of the entity that holds the intellectual property (IP) rights for this asset (e.g., league name, broadcaster, production company, athlete NIL rights holder). Determines licensing obligations and revenue share arrangements.',
    `rights_type` STRING COMMENT 'Classification of the media rights granted for this asset. Determines which distribution channels are permitted. NIL refers to Name, Image, and Likeness rights for athlete-associated content. [ENUM-REF-CANDIDATE: broadcast|ott|social|editorial|all_media|nil|ppv|archive — promote to reference product]. Valid values are `broadcast|ott|social|editorial|all_media|nil`',
    `sport_discipline` STRING COMMENT 'Sport or entertainment discipline associated with the asset (e.g., NFL, NBA, MLB, NHL, MLS, UFC, FIFA, concert, esports). Enables domain-specific filtering, rights segmentation, and league-aligned distribution workflows. [ENUM-REF-CANDIDATE: NFL|NBA|MLB|NHL|MLS|UFC|FIFA|ATP|concert|esports — promote to reference product]',
    `storage_path` STRING COMMENT 'Internal storage path or object storage URI (e.g., S3 bucket path, NAS mount path) where the master media file is archived in the DAM storage tier. Used for file retrieval, backup verification, and disaster recovery operations.',
    `subtype` STRING COMMENT 'Secondary classification providing granular categorisation within the asset type (e.g., highlight_clip, press_photo, podcast_episode, match_report, story_reel, fan_submission). Supports editorial workflow segmentation and metadata-driven distribution rules. [ENUM-REF-CANDIDATE: highlight_clip|full_match|press_photo|podcast_episode|match_report|story_reel|fan_submission|interview|promo_spot|behind_scenes — promote to reference product]',
    `tags_keywords` STRING COMMENT 'Comma-separated list of editorial metadata tags and keywords associated with the asset (e.g., athlete names, team names, event names, competition rounds). Supports full-text search, AI/ML content recommendation, and Adobe Experience Platform personalisation.',
    `thumbnail_url` STRING COMMENT 'URL of the representative thumbnail image for the asset, used in DAM browse interfaces, OTT content catalogues, and digital platform content cards. Auto-generated or manually selected by the editorial team.. Valid values are `^https?://.+`',
    `title` STRING COMMENT 'Human-readable title or display name of the digital content asset as catalogued in Dalet Galaxy. Used for search, discovery, and editorial labelling across OTT, broadcast, and digital platforms.',
    `version_number` STRING COMMENT 'Sequential version number of the asset, incremented each time the asset is revised, re-edited, or re-ingested. Supports version control, editorial rollback, and audit trail requirements within the Dalet Galaxy DAM versioning framework.',
    CONSTRAINT pk_asset PRIMARY KEY(`asset_id`)
) COMMENT 'Core master entity representing every digital content asset managed in Dalet Galaxy DAM — video highlights, photography, audio clips, editorial articles, social media assets, and UGC. SSOT for all content asset identity, format metadata, file specifications, ingest status, lifecycle state, and tag associations across OTT, broadcast, and digital platforms. Serves as the central node connecting rights, production, distribution, and analytics workflows.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`production_order` (
    `production_order_id` BIGINT COMMENT 'Unique surrogate identifier for the production order record within the Dalet Galaxy DAM system. Primary key for the production_order data product in the Silver Layer lakehouse.',
    `activation_id` BIGINT COMMENT 'Foreign key linking to sponsorship.sponsorship_activation. Business justification: A sponsorship activation (e.g., branded halftime show, jersey reveal) triggers a production order to create the required creative. Linking production_order to sponsorship_activation supports activatio',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Production orders are planned against approved budgets. Finance tracks production spend vs. budget at the production order level for variance analysis and financial control. This link enables real-tim',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Production orders for sponsored, NIL, or broadcast content must comply with specific policies (branded content policy, NIL policy, broadcast standards). The production_order has nil_clearance_required',
    `contest_id` BIGINT COMMENT 'Foreign key linking to gaming.contest. Business justification: Production teams create DFS slate preview videos, contest explainer content, and promotional packages commissioned for specific gaming contests. Linking production_order to contest enables cost tracki',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Production orders incur costs (production_cost field) that must be allocated to a cost center for budget vs. actuals reporting. This is a fundamental financial control in content operations. cost_cent',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Sponsored production orders must be traceable to the deal that funds them for cost allocation, billing milestone tracking, and deal fulfillment reporting. Production cost is a deal obligation; finance',
    `facility_id` BIGINT COMMENT 'Foreign key linking to venue.facility. Business justification: Venue operations commission facility-specific production orders for in-venue digital displays, scoreboard content, and concourse signage. Linking production_order to facility enables facility-level co',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Production orders must be attributed to fiscal periods for budget variance reporting and period-end cost accruals. Sports entertainment finance teams track production spend by fiscal period against se',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Production orders are commissioned by or on behalf of specific franchises (team-branded content, franchise documentary series, locker-room access productions). Franchise-level production commissioning',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Production orders incur costs (crew, studio, editing) that must be posted to specific GL accounts for cost accounting and financial close. In sports entertainment ERP operations, every production cost',
    `investigation_id` BIGINT COMMENT 'Foreign key linking to compliance.investigation. Business justification: Production orders may be suspended due to compliance investigations (athlete under investigation cannot appear in content, sponsor under investigation). Compliance and production teams need this link ',
    `league_id` BIGINT COMMENT 'Reference to the sports league or competition governing body associated with the content being produced. Determines applicable rights agreements, branding guidelines, and content governance rules (e.g., NFL, NBA, FIFA, MLS).',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Production orders are scoped to league seasons for production budgeting, scheduling, and rights clearance planning. Production departments plan content output by season (e.g., season preview packages,',
    `match_result_id` BIGINT COMMENT 'Foreign key linking to event.match_result. Business justification: Post-match production orders (highlight reels, press conference clips, stat graphics) are triggered by result confirmation. production_order has fixture_id but not match_result_id; result confirmation',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: NIL clearance workflow: production orders for athlete-featuring branded content must reference the governing NIL agreement before production begins. production_order.nil_clearance_required flag confir',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff content production is commissioned as a distinct workflow with separate budgets, rights clearances, and delivery schedules tied to bracket progression. Production orders for playoff packages r',
    `asset_id` BIGINT COMMENT 'Reference to the primary source media asset in the Dalet Galaxy DAM from which this production order is derived (e.g., raw match footage, raw interview recording, raw photography). Enables lineage tracing from produced output back to source material.',
    `athlete_profile_id` BIGINT COMMENT 'Reference to the primary athlete featured in the content production order. Relevant for highlight packages, athlete profile features, and NIL (Name, Image, and Likeness) content. Triggers NIL rights clearance checks and athlete approval workflows where applicable.',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event that this production order is associated with (e.g., a specific match, concert, or league game). Links content production to the source event for scheduling alignment and rights traceability.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Production orders for broadcast content, sponsored content, and live events are attributed to profit centers for P&L reporting by business unit. Sports entertainment media operations track production ',
    `sku_catalog_id` BIGINT COMMENT 'Foreign key linking to merchandise.sku_catalog. Business justification: Content production orders for product photography, unboxing videos, and athlete endorsement content are commissioned per specific SKU. Merchandise and content teams track production costs against indi',
    `sponsor_id` BIGINT COMMENT 'Reference to a sponsor or commercial partner associated with this production order, where content is produced as part of a sponsorship or branded content agreement. Triggers additional compliance checks for sponsored content disclosure requirements.',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Production orders are commissioned at tournament level (e.g., championship highlight packages, tournament recap films). Producers need to track all production orders against a tournament for budget ma',
    `actual_delivery_date` TIMESTAMP COMMENT 'The actual timestamp when the completed production order was delivered to the distribution channel or CDN. Compared against the deadline to measure SLA adherence and production team performance. Null until delivery is confirmed.',
    `approved_timestamp` TIMESTAMP COMMENT 'Timestamp when the production order received final editorial approval from the commissioning editor or editorial review board. Marks the transition from review to delivery-ready state. Null until approval is granted.',
    `aspect_ratio` STRING COMMENT 'Target aspect ratio for video and image production orders. Determines the visual framing for the output asset. 16:9 is standard broadcast/OTT; 9:16 is vertical for social media stories; 1:1 is square for social feeds. Null for non-visual content types.. Valid values are `16:9|9:16|1:1|4:3|4:5|21:9`',
    `billing_rate` DECIMAL(18,2) COMMENT 'The rate at which this employees time on this production order is billed against the production cost center, expressed in local currency per hour. May vary by role, production type, or CBA agreement. Belongs to the assignment, not to the employee master record (which holds base salary) or the production order (which does not hold per-person rates).',
    `brief_description` STRING COMMENT 'Short editorial brief or production description summarising the creative intent, story angle, or technical specification of the content to be produced. Provides context for assigned editors, producers, and journalists on the scope and purpose of the work order.',
    `cdn_delivery_url` STRING COMMENT 'The CDN (Content Delivery Network) endpoint URL where the produced content asset has been published and is accessible for distribution. Populated upon successful delivery. Used by OTT platforms, digital editorial systems, and social media publishing tools to retrieve the asset.. Valid values are `^https://[a-zA-Z0-9._/-]+$`',
    `content_domain_code` BIGINT COMMENT 'Reference to the content domain or channel category this production order belongs to (e.g., OTT platform, social media, broadcast, digital editorial). Determines distribution pathway and rights clearance requirements.',
    `cost_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the production cost amount (e.g., USD, GBP, EUR). Required for multi-currency financial reporting and SAP S/4HANA FI integration.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording when the production order record was first created in the Dalet Galaxy DAM and ingested into the Silver Layer lakehouse. Distinct from the requested_date business event timestamp. Used for data lineage and audit trail.',
    `deadline` TIMESTAMP COMMENT 'Hard deadline by which the production order must be completed and delivered. Drives SLA monitoring, priority escalation, and resource scheduling. For broadcast segments, this is typically tied to the broadcast transmission schedule. For social cuts, it is tied to the event window.',
    `duration_seconds` STRING COMMENT 'Target runtime duration in seconds for video, audio, or broadcast segment production orders. Null for editorial/text-based content types. Used for scheduling, CDN storage estimation, and broadcast slot planning.',
    `editorial_approval_status` STRING COMMENT 'Status of the editorial review and approval workflow for this production order. Tracks whether the content has been submitted for editorial review, approved for publication, rejected, or sent back for revision. Distinct from the overall order status — an order may be in_production while editorial approval is pending.. Valid values are `not_submitted|pending|approved|rejected|revision_requested`',
    `editorial_notes` STRING COMMENT 'Free-text notes from the commissioning editor or editorial reviewer providing feedback, revision instructions, or approval commentary. Captured during the editorial approval workflow in Dalet Galaxy. Supports iterative content refinement and audit trail for editorial decisions.',
    `end_date` DATE COMMENT 'The date on which this employees assignment to the production order concludes. May differ from the production order deadline if the employees contribution is scoped to a subset of the production timeline.',
    `hours_allocated` DECIMAL(18,2) COMMENT 'The planned number of hours this employee is expected to contribute to this production order in their assigned role. Used for capacity planning, workload balancing, and production cost estimation. This value is specific to the employee-order-role combination and cannot reside on either entity alone.',
    `is_sponsored_content` BOOLEAN COMMENT 'Indicates whether this production order is for sponsored or branded content produced under a commercial partnership agreement. When true, FCC-mandated sponsored content disclosure labels must be applied to the output asset before distribution.',
    `language_code` STRING COMMENT 'ISO 639-1 language code (optionally with ISO 3166-1 region suffix) for the primary language of the produced content (e.g., en, en-US, es-MX, fr-FR, pt-BR). Supports multi-language content production for global markets and OTT localisation workflows.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `nil_clearance_required` BOOLEAN COMMENT 'Indicates whether Name, Image, and Likeness (NIL) rights clearance is required for this production order due to featured athlete content. When true, the order cannot be delivered without confirmed NIL clearance from the athlete or their representative.',
    `order_number` STRING COMMENT 'Externally-known, human-readable business identifier for the production order as assigned by Dalet Galaxy. Used by editorial and production teams to reference work orders in communications, scheduling boards, and delivery manifests.. Valid values are `^PO-[0-9]{4}-[0-9]{6}$`',
    `order_status` STRING COMMENT 'Current lifecycle state of the production order within the Dalet Galaxy workflow. Tracks progression from initial draft through assignment, active production, editorial review, approval, and final delivery or cancellation. [ENUM-REF-CANDIDATE: draft|assigned|in_production|pending_review|approved|delivered|cancelled — promote to reference product]',
    `order_type` STRING COMMENT 'Classifies the nature of the production work order. Distinguishes between technical production types (video highlight packages, social cuts, broadcast segments, audio packages) and editorial commissioning types (editorial features, commissioned editorial/articles). Drives workflow routing in Dalet Galaxy. [ENUM-REF-CANDIDATE: video_highlight|editorial_feature|social_cut|broadcast_segment|audio_package|commissioned_editorial — promote to reference product]. Valid values are `video_highlight|editorial_feature|social_cut|broadcast_segment|audio_package|commissioned_editorial`',
    `output_format` STRING COMMENT 'Technical output format specification for the produced content asset. For video: codec, resolution, and container format (e.g., H.264 1080p MP4, ProRes 4K MOV). For audio: bitrate and format (e.g., AAC 320kbps). For editorial: file format (e.g., HTML, DOCX). Drives technical delivery requirements in Dalet Galaxy.',
    `priority` STRING COMMENT 'Editorial and operational priority level assigned to the production order. Critical priority is reserved for breaking news, live event highlights, and time-sensitive broadcast segments. Drives queue ordering in Dalet Galaxy production workflows.. Valid values are `critical|high|medium|low`',
    `production_cost` DECIMAL(18,2) COMMENT 'Estimated or actual cost incurred to produce the content order, in the operating currency. Includes editor/producer time, freelancer fees, licensing costs, and technical production expenses. Used for content ROI analysis, budget tracking, and EBITDA reporting. Classified as confidential business financial data.',
    `production_stage` STRING COMMENT 'Current stage within the content production workflow pipeline. Tracks granular progress within the broader order status. Briefing covers initial creative direction; pre-production covers asset gathering and scripting; production covers active editing/writing; post-production covers finishing and QC; review covers editorial approval; delivery covers CDN publishing.. Valid values are `briefing|pre_production|production|post_production|review|delivery`',
    `requested_date` TIMESTAMP COMMENT 'The principal business event timestamp recording when the production order was formally raised and submitted in Dalet Galaxy. Represents the real-world moment the content production request was initiated, distinct from system audit timestamps.',
    `rights_clearance_status` STRING COMMENT 'Current status of Digital Rights Management (DRM) clearance for the content being produced. Indicates whether all necessary rights (music, athlete likeness, broadcast footage, third-party IP) have been cleared for the intended distribution channel. Blocked orders cannot proceed to delivery without rights resolution.. Valid values are `pending|cleared|restricted|blocked|partial`',
    `role_on_production` STRING COMMENT 'The specific crew role this employee fulfills on this production order. Determines responsibilities, billing rate applicability, and scheduling requirements. Belongs to the assignment, not to the employee (who may serve different roles on different orders) or the production order (which has multiple roles filled by different people).',
    `scheduled_publish_date` DATE COMMENT 'The planned calendar date on which the produced content asset is scheduled for publication or broadcast. Used for editorial calendar planning and CDN pre-positioning. May differ from the production deadline if content is produced in advance.',
    `start_date` DATE COMMENT 'The date on which this employees assignment to the production order begins. Used for crew scheduling, capacity planning, and determining active assignments. Belongs to the assignment record, not to the employee or the order independently.',
    `story_angle` STRING COMMENT 'The editorial perspective, narrative framing, or journalistic angle for the content piece. Applicable primarily to editorial features, commissioned articles, and interview content. Guides the journalist or writer on the intended narrative direction and audience focus.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the primary geographic territory for which this content is being produced and cleared for distribution. Drives territorial rights enforcement, geo-blocking rules on CDN, and regional broadcast compliance.. Valid values are `^[A-Z]{3}$`',
    `title` STRING COMMENT 'Human-readable title or working headline of the content piece being produced. For video highlights this is the clip title; for editorial features it is the article headline or working title; for social cuts it is the post caption concept. Used in editorial planning boards and content calendars.',
    `ugc_flag` BOOLEAN COMMENT 'Indicates whether this production order involves User-Generated Content (UGC) as source material. UGC-sourced orders require additional rights clearance and moderation workflows before publication. Impacts DRM clearance and editorial approval processes.',
    `updated_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording when the production order record was most recently modified in the source system or Silver Layer. Used for incremental data pipeline processing, change detection, and audit trail compliance.',
    `word_count_target` STRING COMMENT 'Target word count for editorial content types (articles, features, interviews, commissioned editorial). Null for non-editorial production types such as video highlights or audio packages. Used for editorial planning and writer briefing.',
    CONSTRAINT pk_production_order PRIMARY KEY(`production_order_id`)
) COMMENT 'Transactional record capturing content production work orders within Dalet Galaxy — covering video highlight packages, editorial features (story angle, journalist assignment, word count targets), social cuts, broadcast segments, and commissioned editorial content. Tracks assignment, production stage, priority, deadline, assigned editor/producer, output specifications, delivery status, and editorial approval workflow. Supports both technical production (video editing, audio mixing) and editorial commissioning (articles, features, interviews) as order types.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`ingest_job` (
    `ingest_job_id` BIGINT COMMENT 'Unique surrogate identifier for each content ingest job record in the Digital Asset Management (DAM) system. Primary key for the ingest_job data product.',
    `asset_id` BIGINT COMMENT 'Reference to the DAM content asset record created or updated as a result of this ingest job. Establishes traceability from raw ingest event to registered DAM asset identity.',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Content ingest jobs systematically process media that may contain personal data (athlete biometrics, fan footage from venues). GDPR Article 30 requires data processing records for systematic ingestion',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Content ingest jobs for franchise-produced footage (team media feeds, club-owned content) require franchise attribution for rights ownership tracking and distribution clearance. Sports content operati',
    `game_result_id` BIGINT COMMENT 'Foreign key linking to league.game_result. Business justification: Post-game broadcast ingest workflows reference the game result for automated metadata tagging (score, teams, OT status), QC validation, and rights clearance. Ingest operations teams use game_result to',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: Content ingest jobs sourced from live broadcasts must reference the originating live feed for MAM/DAM integration. Content operations teams track which live feed produced each ingest job for quality c',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Content ingest jobs must validate rights clearance against the governing media rights deal before ingesting and distributing content. Rights compliance during ingest is a regulatory requirement in spo',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff broadcast ingestion operates under bracket-specific rights clearance rules and distribution restrictions. Ingest jobs for playoff content require bracket context to apply correct DRM schemes, ',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event associated with the ingested content (e.g., match, concert, press conference). Links ingest jobs to the event scheduling and production context.',
    `production_order_id` BIGINT COMMENT 'Foreign key linking to content.production_order. Business justification: Ingest jobs are often initiated as part of a production order workflow. Linking ingest_job to production_order enables tracking which production work order triggered the ingest, supporting production ',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Ingest jobs process season-specific broadcast feeds and archive content under season-scoped rights agreements. Season-level ingest tracking is required for content archiving compliance, rights window ',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Broadcast content ingestion workflows are organized at tournament level for bulk ingest operations (e.g., ingesting all match footage for a tournament). Operations teams track ingest jobs per tourname',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where the content was captured. Supports geographic and operational reporting on ingest activity by venue.',
    `broadcast_rights_flag` BOOLEAN COMMENT 'Indicates whether the ingested content carries cleared broadcast distribution rights for linear television and RSN (Regional Sports Network) channels. True = broadcast rights confirmed; False = broadcast rights not cleared or not applicable.',
    `cdn_distribution_status` STRING COMMENT 'Status of the CDN (Content Delivery Network) distribution push for this ingested asset following successful DAM registration. Tracks whether the asset has been propagated to CDN edge nodes for OTT and digital platform delivery.. Valid values are `not_distributed|queued|distributed|failed`',
    `checksum_algorithm` STRING COMMENT 'The hashing algorithm used to generate the file integrity checksum for this ingest job. Used to verify that files were transferred without corruption from source to DAM storage.. Valid values are `MD5|SHA-1|SHA-256|SHA-512|xxHash`',
    `checksum_value` DECIMAL(18,2) COMMENT 'The computed checksum hash value for the primary file or manifest package of this ingest job. Validated against the source-declared checksum to confirm file integrity upon arrival in the DAM.',
    `completed_timestamp` TIMESTAMP COMMENT 'Timestamp recording when the ingest job reached a terminal state (completed, failed, or cancelled). Used alongside ingest_timestamp to calculate ingest_duration_seconds and for SLA compliance reporting.',
    `content_date` DATE COMMENT 'The calendar date on which the content was originally captured or created, as declared by the source system or embedded metadata. May differ from ingest_timestamp if content is ingested after the fact (e.g., archival uploads).',
    `content_type` STRING COMMENT 'Classification of the media type being ingested. Covers video highlights, photography, audio recordings, editorial content, social media assets, and User-Generated Content (UGC). Drives downstream DAM workflow routing and metadata schema selection.. Valid values are `video|photo|audio|editorial|social_asset|ugc`',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this ingest job record was first created in the DAM system. Used for data lineage, audit trails, and Silver layer traceability.',
    `destination_storage_path` STRING COMMENT 'The target storage path or URI in the DAM or cloud storage layer where the ingested content is written upon successful completion. Supports traceability from raw capture to registered DAM asset location.',
    `drm_clearance_status` STRING COMMENT 'Rights clearance status for the ingested content under the Digital Rights Management (DRM) framework. Determines whether the asset is cleared for distribution across OTT, broadcast, social, and digital channels.. Valid values are `cleared|pending|restricted|blocked`',
    `duration_seconds` DECIMAL(18,2) COMMENT 'Duration of the ingested video or audio content in seconds. Used for rights clearance calculations, broadcast scheduling, and content catalogue metadata.',
    `error_code` STRING COMMENT 'Standardized error code returned by the DAM ingest pipeline when the job encounters a failure condition. Populated only for failed or on-hold jobs. Used for automated alerting, root cause analysis, and SLA reporting.',
    `file_count` STRING COMMENT 'Total number of individual files included in this ingest job as declared in the file manifest. Used to validate completeness of ingest against expected file count.',
    `file_manifest_path` STRING COMMENT 'Storage path or URI to the file manifest document listing all individual files included in this ingest job. The manifest captures filenames, sizes, checksums, and sequence information for multi-file ingest packages.',
    `frame_rate` DECIMAL(18,2) COMMENT 'Frames per second of the ingested video content. Standard values include 23.976, 25, 29.97, 50, 59.94, and 60 fps. Critical for broadcast compliance and transcoding pipeline configuration.',
    `ingest_channel` STRING COMMENT 'The operational channel through which this ingest job was initiated. Distinguishes between manual operator-triggered ingests, fully automated pipeline ingests, scheduled batch ingests, and API-driven ingests from external systems.. Valid values are `manual|automated|scheduled|api`',
    `ingest_duration_seconds` DECIMAL(18,2) COMMENT 'Elapsed time in seconds from ingest job initiation to completion or failure. Used for SLA (Service Level Agreement) compliance monitoring, pipeline performance benchmarking, and capacity planning.',
    `ingest_priority` STRING COMMENT 'Business priority level assigned to this ingest job, governing queue position and resource allocation in the DAM ingest pipeline. Critical priority is used for live event highlights requiring immediate OTT/social distribution.. Valid values are `critical|high|normal|low`',
    `ingest_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp recording when the content ingest process was initiated and the raw asset capture began entering the DAM pipeline. Distinct from record audit timestamps.',
    `is_ugc` BOOLEAN COMMENT 'Indicates whether the ingested content is User-Generated Content (UGC) submitted by fans or external contributors rather than produced by the organizations own production teams. UGC assets require additional rights clearance and moderation workflows.',
    `job_reference_number` STRING COMMENT 'Externally-known business identifier for the ingest job, used by production teams and operations staff to reference and track a specific ingest event across systems. Follows the format INJ-{YEAR}-{SEQUENCE}.. Valid values are `^INJ-[0-9]{4}-[0-9]{6}$`',
    `job_status` STRING COMMENT 'Current lifecycle state of the ingest job within the DAM workflow. Tracks progression from initial queuing through active processing to terminal states (completed, failed, cancelled). [ENUM-REF-CANDIDATE: queued|in_progress|completed|failed|cancelled|on_hold — promote to reference product]. Valid values are `queued|in_progress|completed|failed|cancelled|on_hold`',
    `metadata_extraction_status` STRING COMMENT 'Status of the automated metadata extraction process that reads technical and descriptive metadata from the ingested files (e.g., EXIF, XMP, embedded timecode, audio levels). Drives DAM catalogue completeness.. Valid values are `pending|completed|partial|failed`',
    `metadata_profile` STRING COMMENT 'The metadata schema profile applied during extraction and tagging for this ingest job (e.g., sports_event_video, ugc_social, broadcast_highlight, editorial_photo). Determines which metadata fields are populated in the DAM asset record.',
    `moderation_status` STRING COMMENT 'Editorial moderation status for ingested content, particularly applicable to UGC (User-Generated Content) and social media assets. Indicates whether the content has been reviewed and approved for DAM registration and distribution.. Valid values are `not_required|pending|approved|rejected`',
    `ott_rights_flag` BOOLEAN COMMENT 'Indicates whether the ingested content carries cleared OTT (Over-The-Top Streaming) distribution rights for DTC (Direct-To-Consumer) streaming platforms. True = OTT rights confirmed; False = OTT rights not cleared.',
    `primary_format` STRING COMMENT 'The dominant file format or codec of the ingested content (e.g., MXF, MP4, MOV, RAW, JPEG, WAV, MP3). Determines transcoding requirements and DAM storage profile. [ENUM-REF-CANDIDATE: MXF|MP4|MOV|RAW|JPEG|TIFF|WAV|MP3|AIFF|PDF — promote to reference product]',
    `qc_failure_reason` STRING COMMENT 'Descriptive reason code or message explaining why the quality check failed. Populated only when qc_status is failed. Supports remediation workflows and root cause analysis.',
    `qc_score` DECIMAL(18,2) COMMENT 'Numeric quality score assigned by the automated QC engine during ingest validation. Expressed as a percentage (0.00–100.00). Scores below threshold trigger QC failure and manual review routing.',
    `qc_status` STRING COMMENT 'Result of the automated and/or manual quality check performed on the ingested content. Indicates whether the asset meets technical and editorial standards required for DAM registration and downstream distribution.. Valid values are `pending|passed|failed|waived|under_review`',
    `resolution` STRING COMMENT 'Video resolution classification of the ingested content. Applicable to video and photo assets. Drives transcoding profiles, storage tier assignment, and OTT/broadcast distribution suitability.. Valid values are `SD|HD|2K|4K|8K|UHD`',
    `retry_count` STRING COMMENT 'Number of times this ingest job has been retried following a failure or interruption. Tracks pipeline resilience and identifies problematic source feeds or assets requiring manual intervention.',
    `rights_territory` STRING COMMENT 'Geographic territory or territories for which rights have been cleared for this ingested content. Expressed as ISO 3166-1 alpha-3 country codes or territory group codes (e.g., USA, GBR, WORLDWIDE). Governs CDN distribution routing.',
    `source_device_identifier` STRING COMMENT 'Unique identifier of the physical device or system that captured or submitted the content (e.g., camera serial number, OB truck unit ID, social feed connector ID). Supports chain-of-custody traceability and device-level quality diagnostics.',
    `source_system_code` BIGINT COMMENT 'Reference to the originating system or device that submitted the content for ingest (e.g., Outside Broadcast truck, camera card reader, social media feed connector, UGC upload portal). Links to the content source system registry.',
    `source_type` STRING COMMENT 'Classification of the physical or digital origin of the content being ingested. Distinguishes between Outside Broadcast (OB) truck feeds, camera card transfers, social media feeds, User-Generated Content (UGC) uploads, broadcast feeds, and API push integrations. [ENUM-REF-CANDIDATE: ob_truck|camera_card|social_feed|ugc_upload|broadcast_feed|api_push|satellite_feed|ftp_transfer — promote to reference product]. Valid values are `ob_truck|camera_card|social_feed|ugc_upload|broadcast_feed|api_push`',
    `storage_tier` STRING COMMENT 'Storage tier classification assigned to the ingested content based on access frequency and retention policy. Hot tier for active production assets, warm for recent archive, cold for long-term retention, archive for compliance-only storage.. Valid values are `hot|warm|cold|archive`',
    `total_file_size_mb` DECIMAL(18,2) COMMENT 'Aggregate size in megabytes of all files included in this ingest job as declared in the manifest. Used for storage capacity planning, CDN bandwidth tracking, and ingest throughput reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this ingest job record was last modified in the DAM system. Supports change tracking and incremental Silver layer processing.',
    CONSTRAINT pk_ingest_job PRIMARY KEY(`ingest_job_id`)
) COMMENT 'Transactional record for each content ingest event into the DAM — capturing source system (OB truck, camera card, social feed, UGC upload), ingest timestamp, file manifest, quality check status, metadata extraction results, and destination storage path. Supports traceability from raw capture to DAM registration.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`publish_event` (
    `publish_event_id` BIGINT COMMENT 'Unique surrogate identifier for each content publication or distribution event record in the Silver layer. Primary key for the publish_event data product.',
    `asset_id` BIGINT COMMENT 'Reference to the content asset being published — video highlight, photograph, audio clip, editorial piece, or UGC item managed in the Digital Asset Management (DAM) system. Links to the content asset master record.',
    `betting_market_id` BIGINT COMMENT 'Foreign key linking to gaming.betting_market. Business justification: Broadcast-linked wagering: when a live content publish_event goes live (stream activation), it triggers or is associated with the opening of a corresponding betting market — a named operational proces',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: Content publish events for broadcast distribution must be coordinated with the broadcast schedule slot. Content operations teams need to link publish events to broadcast schedule entries to synchroniz',
    `contest_id` BIGINT COMMENT 'Foreign key linking to gaming.contest. Business justification: Content publication is coordinated with DFS/bracket contest registration opening — promotional videos, slate previews, and contest explainers are published at contest launch. The publish_event workflo',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Publishing content containing personal data to platforms constitutes a data processing activity requiring GDPR Article 30 documentation. Compliance officers must link each publish event to the authori',
    `emergency_activation_id` BIGINT COMMENT 'Foreign key linking to security.emergency_activation. Business justification: Emergency activations set broadcast_interrupted=true and can cause live publish events to be suspended or taken down. Linking the publish_event to the triggering emergency_activation is required for b',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Publish events (PPV, OTT, broadcast) trigger revenue recognition that must be attributed to the correct fiscal period for financial close and SEC reporting. Sports entertainment finance requires publi',
    `fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event (match, game, concert, tournament) that this content asset is associated with. Enables event-level content distribution analytics and rights traceability.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Publish events distribute franchise-specific content under franchise territorial rights and sponsor agreements. Franchise-scoped publish tracking is required for revenue attribution, territorial right',
    `investigation_id` BIGINT COMMENT 'Foreign key linking to compliance.investigation. Business justification: Publish events may be blocked or triggered for takedown due to active compliance investigations. The publish_event has takedown_reason and takedown_timestamp fields; linking to the investigation recor',
    `league_id` BIGINT COMMENT 'Reference to the league or governing body (NFL, NBA, MLB, NHL, MLS, FIFA, etc.) whose content rights govern this distribution event. Supports league-level rights compliance and content attribution reporting.',
    `license_id` BIGINT COMMENT 'Foreign key linking to content.content_license. Business justification: Publish events distribute content under a specific content license. Linking publish_event to content_license enables license compliance verification for each distribution event and supports license us',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the specific broadcast or media rights agreement under which this content distribution is authorized. Ensures every publish event is traceable to a valid rights contract for IP compliance and audit.',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: A publish event distributes content to a specific platform channel. platform_channel_name is a denormalized STRING that should be replaced by a FK to platform_channel.platform_channel_id, enabling JOI',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff content publishing follows bracket-specific rights windows, geo-restrictions, and PPV rules that differ from regular season. Publish events for playoff content reference the bracket to enforce',
    `activation_id` BIGINT COMMENT 'Reference to the sponsorship or advertising overlay package applied to this content distribution event. Links to the sponsorship management record for brand attribution, CPM (Cost Per Mille) reporting, and sponsor compliance.',
    `primary_publish_fixture_id` BIGINT COMMENT 'Reference to the sports or entertainment event (match, game, concert, tournament) that this content asset is associated with. Enables event-level content distribution analytics and rights traceability.',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to merchandise.promotion. Business justification: Content publish events (product launch videos, limited-edition drop announcements) are executed in coordination with merchandise promotions. Campaign operations teams track which publish events are ti',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Publish events distribute content within season-specific rights windows. OTT and broadcast rights compliance requires season-scoped publish tracking — content published outside its licensed season win',
    `segment_id` BIGINT COMMENT 'Foreign key linking to fan.segment. Business justification: Segment-targeted content publishing: sports entertainment OTT/DTC platforms publish content to specific fan segments (e.g., premium members only, regional audience). This FK enables publish workflow a',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Content publishing in sports entertainment is organized by tournament for distribution reporting and rights enforcement (e.g., all tournament content published under a single rights deal). Distributio',
    `asset_duration_seconds` STRING COMMENT 'Duration of the published content asset in seconds. Used for CDN bandwidth estimation, broadcast scheduling slot validation, and platform-specific duration compliance checks (e.g., social media clip length limits).',
    `asset_file_size_mb` DECIMAL(18,2) COMMENT 'File size of the published content asset in megabytes at the time of distribution. Supports CDN cost allocation, bandwidth consumption tracking, and storage capacity planning.',
    `cdn_endpoint_url` STRING COMMENT 'The Content Delivery Network (CDN) URL from which the published content asset is served to end consumers. Provides the operational delivery address for playback, download, or streaming on the target platform.',
    `content_rating` STRING COMMENT 'Audience content rating classification applied to the asset at time of publication. Governs platform eligibility, parental controls, and regulatory compliance for broadcast and OTT distribution. [ENUM-REF-CANDIDATE: G|PG|PG-13|R|TV-MA|TV-14|TV-PG|NR — promote to reference product]',
    `content_type` STRING COMMENT 'Classification of the content asset being distributed. Drives downstream packaging, encoding, and Digital Rights Management (DRM) rules applied during distribution.. Valid values are `video|photo|audio|editorial|ugc|social_graphic`',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this publish event record was first created in the system. Used for data lineage, audit trail compliance, and Silver layer ingestion tracking.',
    `distribution_notes` STRING COMMENT 'Free-text operational notes recorded by content operations staff regarding this publish event. May include special handling instructions, rights clearance notes, or platform-specific configuration details.',
    `distribution_reference_number` STRING COMMENT 'Externally-known business identifier for this publish event, sourced from Dalet Galaxy distribution workflow. Used for cross-system reconciliation and audit trail tracking across CDN, OTT, and broadcast systems.',
    `distribution_status` STRING COMMENT 'Current lifecycle state of the content publication event. Tracks the workflow from initial queue through active distribution to final published or failed terminal states. Supports operational monitoring and SLA compliance reporting.. Valid values are `queued|in_progress|published|failed|retrying|withdrawn`',
    `drm_license_url` STRING COMMENT 'The URL endpoint of the DRM license server used to validate and serve decryption keys for this content distribution. Required for OTT and DTC platform playback authorization and rights enforcement audit.',
    `drm_scheme` STRING COMMENT 'The Digital Rights Management (DRM) packaging technology applied to the content asset during this distribution event. Governs encryption and access control for the published content on the target platform.. Valid values are `widevine|fairplay|playready|aes128|none`',
    `encoding_profile` STRING COMMENT 'The video/audio encoding specification applied to the content asset for this distribution event (e.g., H264_1080p_5Mbps, HEVC_4K_HDR, AAC_128kbps). Supports quality assurance, platform compatibility validation, and CDN bandwidth planning.',
    `failure_reason` STRING COMMENT 'Descriptive reason code or message explaining why a publish event failed or required retry. Populated only when distribution_status is failed or retrying. Supports root cause analysis and SLA reporting.',
    `geo_restriction_applied` BOOLEAN COMMENT 'Indicates whether geographic access restrictions are enforced for this content distribution event. When true, the content is restricted to specific territories based on broadcast rights agreements and regulatory requirements.',
    `geo_restriction_mode` STRING COMMENT 'Defines whether the territory codes in geo_restriction_territory_codes represent an allowlist (content permitted only in listed territories) or a blocklist (content blocked in listed territories). Governs territorial rights enforcement logic.. Valid values are `allowlist|blocklist`',
    `geo_restriction_territory_codes` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes defining the territories where this content is permitted or blocked. Supports broadcast rights territorial enforcement and GDPR/CCPA regional compliance. Example: USA,CAN,GBR.',
    `is_live_content` BOOLEAN COMMENT 'Indicates whether this publish event distributes live or near-live content (e.g., live match stream, live press conference) as opposed to pre-produced or archived content. Drives latency SLA requirements and CDN live-streaming configuration.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this content distribution event is a Pay-Per-View (PPV) monetized event requiring consumer purchase or entitlement validation prior to access. Drives paywall enforcement and revenue attribution.',
    `moderation_status` STRING COMMENT 'The content moderation review status for this publish event, particularly relevant for UGC and social media assets. Ensures only approved content is distributed and supports compliance with platform content policies.. Valid values are `approved|pending|rejected|escalated`',
    `publish_initiated_by` STRING COMMENT 'Indicates how the publish event was triggered — manually by a content operator, automatically by a workflow rule, via an API (Application Programming Interface) call from an external system, or by a scheduled distribution job. Supports operational audit and workflow optimization.. Valid values are `manual|automated|api|scheduled`',
    `publish_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp recording when the content asset was successfully published and made available on the target platform. Distinct from scheduled or requested times. Conforms to yyyy-MM-ddTHH:mm:ss.SSSXXX format.',
    `retry_count` STRING COMMENT 'Number of times this publish event has been retried following a failure. Supports SLA breach analysis, CDN reliability monitoring, and identification of systemic distribution issues.',
    `scheduled_publish_timestamp` TIMESTAMP COMMENT 'The planned date and time at which the content asset was scheduled for publication on the target platform. Used for embargo management, coordinated release windows, and SLA variance analysis against actual publish timestamp.',
    `takedown_reason` STRING COMMENT 'Reason code explaining why a content asset was taken down from the target platform. Supports IP rights enforcement audit, regulatory compliance reporting, and editorial governance review.. Valid values are `rights_expired|dmca_request|editorial_decision|platform_policy|regulatory_order|other`',
    `takedown_timestamp` TIMESTAMP COMMENT 'Timestamp recording when a published content asset was withdrawn or taken down from the target platform. Populated when distribution_status transitions to withdrawn. Supports rights expiry enforcement and DMCA/IP compliance audit.',
    `ugc_source_flag` BOOLEAN COMMENT 'Indicates whether the content asset being distributed originated as User-Generated Content (UGC). UGC assets require additional rights clearance workflows and moderation approval before distribution.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this publish event record was last modified. Tracks status transitions, retry attempts, and metadata corrections for operational and compliance audit purposes.',
    `workflow_job_reference` STRING COMMENT 'The Dalet Galaxy distribution workflow job identifier associated with this publish event. Enables cross-system traceability between the Silver layer record and the source DAM workflow execution for debugging and audit.',
    CONSTRAINT pk_publish_event PRIMARY KEY(`publish_event_id`)
) COMMENT 'Transactional record of each content publication or distribution event — capturing asset, target platform (OTT, social, CDN, broadcast), publish timestamp, distribution status, CDN endpoint, geo-restriction applied, and DRM packaging applied. Provides the audit trail for all content distribution activity.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`metadata_tag` (
    `metadata_tag_id` BIGINT COMMENT 'Unique surrogate identifier for each controlled vocabulary metadata tag record in the Digital Asset Management (DAM) system. Primary key for the metadata_tag master record. [_canonical_skip_reason: MASTER_RESOURCE role — this is a controlled vocabulary tag asset managed in Dalet Galaxy DAM with its own identity and lifecycle.]',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: metadata_tag carries league_code as a plain denormalized attribute. Normalizing to league_id enables league-specific tag governance, rights-sensitive tagging policies, and league-branded taxonomy mana',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Metadata tags with compliance_flag=true or is_rights_sensitive=true are mandated by specific compliance policies (rights sensitivity policy, NIL tagging policy). Linking tags to their governing policy',
    `alias_terms` STRING COMMENT 'Pipe-delimited list of alternative names, synonyms, or common misspellings associated with this tag (e.g., Football|Footy|Association Football for the Soccer tag). Used to enhance search recall, support natural language queries, and map legacy tag names to current controlled vocabulary terms during DAM migration.',
    `auto_tagging_confidence_threshold` DECIMAL(18,2) COMMENT 'Minimum confidence score (0.0000 to 1.0000) required from the auto-tagging AI/ML model before this tag is automatically applied to a content asset without human review. Tags with lower model confidence scores are routed to editorial review queues. Null when auto_tagging_eligible is False.',
    `auto_tagging_eligible` BOOLEAN COMMENT 'Indicates whether this tag may be applied automatically by AI/ML-powered auto-tagging engines integrated with Dalet Galaxy DAM (e.g., computer vision for athlete recognition, speech-to-text for topic detection). When False, the tag requires manual editorial application only.',
    `cdn_cache_ttl_seconds` STRING COMMENT 'Recommended cache Time-To-Live (TTL) in seconds for content assets bearing this tag when served via CDN. Tags associated with live or near-live event content (e.g., breaking news, live match highlights) have shorter TTLs to ensure freshness. Tags for evergreen content have longer TTLs to optimize CDN performance.',
    `compliance_flag` BOOLEAN COMMENT 'Indicates whether this tag is associated with regulatory or compliance-sensitive content categories (e.g., PED/doping-related content, gambling-adjacent content, athlete NIL content, GDPR-sensitive fan data content). When True, additional compliance workflows are triggered in the DAM and distribution systems.',
    `content_type_affinity` STRING COMMENT 'Indicates which content asset types this tag is applicable to within the DAM. Restricts tag availability in editorial workflows to relevant asset types (e.g., a mood tag may apply to video and photo but not editorial). all indicates the tag is applicable across all content types. [ENUM-REF-CANDIDATE: video|photo|audio|editorial|social|ugc|all — 7 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this metadata tag record was first created in the DAM controlled vocabulary registry. Supports audit trail requirements, taxonomy version history, and data lineage tracking in the Silver Layer lakehouse.',
    `dam_category_path` STRING COMMENT 'Full category path within Dalet Galaxy DAM where this tag is classified (e.g., /Sports/Soccer/Leagues/MLS). Used for DAM navigation, bulk asset operations, and workflow routing within the media asset management and broadcast workflow system.',
    `display_priority` STRING COMMENT 'Numeric ordering weight that controls the display sequence of this tag within its taxonomy type in search facets, editorial tag pickers, and fan-facing discovery interfaces. Lower values indicate higher priority display position. Used by DAM editors and OTT platform UX teams to surface the most relevant tags first.',
    `effective_from_date` DATE COMMENT 'Date from which this metadata tag becomes valid and available for application to content assets. Supports seasonal taxonomy management (e.g., a tag for a new league season becomes effective at season start) and planned tag activations aligned with event schedules.',
    `effective_until_date` DATE COMMENT 'Date after which this metadata tag is no longer valid for application to new content assets. Null indicates the tag has no planned expiry. Used for time-bound tags such as event-specific tags (e.g., a Super Bowl LIX tag expires after the event window) and seasonal competition tags.',
    `geo_restriction_scope` STRING COMMENT 'Pipe-delimited list of ISO 3166-1 alpha-3 country codes where content tagged with this tag has distribution restrictions (e.g., USA|CAN for North American blackout). Used by CDN and OTT platforms to enforce territorial rights. Null indicates no geographic restriction. Aligns with RSN blackout and international broadcast rights agreements.',
    `hierarchy_level` STRING COMMENT 'Numeric depth of the tag within the taxonomy hierarchy tree, starting at 1 for root-level tags (e.g., Sport=1, League=2, Team=3, Athlete=4). Used for hierarchical search faceting, breadcrumb navigation, and roll-up reporting in analytics platforms.',
    `hierarchy_path` STRING COMMENT 'Full delimited path from root to this tag in the taxonomy tree (e.g., sport/soccer/league/mls/team/la_galaxy). Enables efficient subtree queries, breadcrumb rendering, and hierarchical filtering in DAM and OTT discovery interfaces without recursive joins.',
    `ip_owner` STRING COMMENT 'Name of the entity that holds Intellectual Property (IP) rights over content associated with this tag (e.g., NFL Properties LLC, FIFA, NBA Properties Inc.). Used for rights clearance workflows, licensing fee calculations, and IP compliance reporting. Critical for league-branded and athlete-branded content tags.',
    `is_personalization_eligible` BOOLEAN COMMENT 'Indicates whether this tag may be used as a personalization signal in fan preference profiles and recommendation engines within Adobe Experience Platform. When True, the tag contributes to fan interest graphs, content affinity scoring, and targeted content delivery for DTC and OTT platforms.',
    `is_rights_sensitive` BOOLEAN COMMENT 'Indicates whether content assets tagged with this tag are subject to Digital Rights Management (DRM) restrictions, broadcast rights windows, or territorial licensing constraints. When True, downstream distribution systems must perform rights clearance checks before serving content. Critical for OTT and CDN distribution compliance.',
    `is_searchable` BOOLEAN COMMENT 'Indicates whether this tag is exposed as a searchable facet in DAM search interfaces, OTT content discovery, and digital platform search indexes. When False, the tag is used for internal classification and workflow routing only and is not surfaced to end users or search APIs.',
    `is_ugc_eligible` BOOLEAN COMMENT 'Indicates whether this tag may be applied to User-Generated Content (UGC) assets submitted by fans or third parties. When True, the tag is available in fan-facing content submission workflows and UGC moderation queues. When False, the tag is restricted to professionally produced content only.',
    `language_code` STRING COMMENT 'ISO 639-1 language code (optionally with ISO 3166-1 region subtag) indicating the language of the tag_name and tag_description fields (e.g., en, es, fr, pt-BR). Supports multilingual taxonomy management for global markets and international broadcast distribution.. Valid values are `^[a-z]{2}(-[A-Z]{2})?$`',
    `last_modified_by` STRING COMMENT 'Username or system identifier of the user or automated process that last modified this metadata tag record. Supports editorial accountability and taxonomy governance audits within Dalet Galaxy DAM and the Silver Layer data product.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this metadata tag record was most recently updated in the DAM controlled vocabulary registry. Used for incremental ETL processing, change data capture, and taxonomy version management in the Silver Layer lakehouse.',
    `nil_applicable` BOOLEAN COMMENT 'Indicates whether this tag is associated with athlete Name, Image, and Likeness (NIL) rights considerations. When True, content assets bearing this tag must be checked against athlete NIL agreements before commercial use, licensing, or sponsorship activation. Particularly relevant for athlete-specific tags.',
    `ott_platform_eligibility` STRING COMMENT 'Pipe-delimited list of OTT and DTC platform identifiers where content tagged with this tag is eligible for distribution (e.g., nfl_plus|espn_plus|peacock). Null indicates no platform-specific restriction. Used by CDN distribution rules and OTT content ingestion pipelines to enforce platform-level rights.',
    `review_required` BOOLEAN COMMENT 'Indicates whether application of this tag to a content asset requires editorial review and approval before the tag association is published. Used for sensitive tags (e.g., athlete injury, disciplinary action, PED-related content) where incorrect tagging carries reputational or legal risk.',
    `rights_restriction_type` STRING COMMENT 'Category of rights restriction applicable to content assets bearing this tag. Territorial restrictions limit distribution by geography; temporal restrictions apply broadcast windows; platform restrictions limit to specific OTT or DTC channels; league blackout enforces RSN blackout rules; PPV exclusive restricts to Pay-Per-View events. Null or none when is_rights_sensitive is False.. Valid values are `territorial|temporal|platform|league_blackout|ppv_exclusive|none`',
    `social_channel_eligibility` STRING COMMENT 'Pipe-delimited list of social media channel identifiers where content tagged with this tag is approved for distribution (e.g., instagram|twitter|tiktok|youtube). Null indicates no social channel restriction. Used by social publishing workflows to enforce league and rights holder social media policies.',
    `source_system` STRING COMMENT 'Operational system of record from which this metadata tag was originated or last synchronized. Dalet Galaxy is the primary DAM source; Adobe Experience Platform may contribute audience-derived tags; Salesforce CRM may contribute sponsor or fan segment tags. Used for data lineage tracking and conflict resolution during ETL.. Valid values are `dalet_galaxy|adobe_experience_platform|salesforce_crm|manual|api_import`',
    `source_tag_reference` STRING COMMENT 'Native identifier of this tag in the originating source system (e.g., Dalet Galaxy internal tag ID, Adobe Experience Platform segment ID). Enables bidirectional synchronization, change detection, and audit tracing between the Silver Layer lakehouse and operational systems.',
    `sport_code` STRING COMMENT 'Standardized sport classification code associated with this tag (e.g., SOC for Soccer, BBL for Basketball, AMF for American Football). Aligns with governing body sport codes from FIFA, NFL, NBA, MLB, NHL, MLS. Null for non-sport-specific tags such as topic or mood tags.. Valid values are `^[A-Z]{2,10}$`',
    `tag_code` STRING COMMENT 'Externally-known, system-unique alphanumeric code identifying the tag within the DAM and digital platforms (e.g., SPORT_SOCCER, LEAGUE_NFL, ATHLETE_LEBRON). Used as the stable business key for API lookups, CDN metadata headers, and cross-system integrations. Sourced from Dalet Galaxy tag registry.. Valid values are `^[A-Z0-9_]{2,50}$`',
    `tag_description` STRING COMMENT 'Editorial description of the tags meaning, scope, and intended usage within the controlled vocabulary. Guides content editors and automated tagging systems on correct application. Includes disambiguation notes for tags with similar names (e.g., distinguishing MLS as Major League Soccer vs. other uses).',
    `tag_name` STRING COMMENT 'Human-readable display label for the metadata tag as shown in the DAM user interface, search facets, and editorial tools (e.g., Soccer, National Football League, LeBron James). Used for content discovery, faceted search, and personalization surfaces.',
    `tag_status` STRING COMMENT 'Current lifecycle state of the metadata tag within the controlled vocabulary. Active tags are available for application to content assets. Deprecated tags are retained for historical asset associations but blocked from new tagging. Draft tags are under editorial review before activation.. Valid values are `active|deprecated|draft|archived|pending_review`',
    `tag_type` STRING COMMENT 'Primary classification category of the tag within the controlled vocabulary taxonomy. Determines which facet the tag belongs to for search, discovery, and rights filtering. [ENUM-REF-CANDIDATE: sport|league|team|athlete|event|topic|mood|content_type|venue|sponsor|geography|season|competition — promote to reference product]',
    `taxonomy_domain` STRING COMMENT 'High-level domain grouping within the controlled vocabulary that the tag belongs to. Supports multi-domain tagging strategies across sport classification, editorial categorization, rights management, commercial/sponsorship, audience segmentation, and production metadata.. Valid values are `sport|editorial|rights|commercial|audience|production`',
    `version_number` STRING COMMENT 'Monotonically incrementing version counter for this metadata tag record, incremented on each update. Supports optimistic concurrency control in DAM workflows, change history tracking, and Silver Layer SCD (Slowly Changing Dimension) management for taxonomy evolution over time.',
    CONSTRAINT pk_metadata_tag PRIMARY KEY(`metadata_tag_id`)
) COMMENT 'Master record for controlled vocabulary metadata tags applied to content assets — including sport, league, team, athlete, event, topic, mood, and content type taxonomies. Supports structured tagging for search, discovery, personalization, and rights filtering across the DAM and digital platforms.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`collection` (
    `collection_id` BIGINT COMMENT 'Unique surrogate identifier for the content collection record in the Sports Entertainment digital asset management platform (Dalet Galaxy DAM). Primary key for the collection entity.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Athlete-curated content collections: sports-entertainment platforms curate collections around specific athletes (career highlight reels, Best of packages). The collection must reference the featured',
    `sponsor_id` BIGINT COMMENT 'Reference to the sponsoring brand or commercial partner associated with this collection for branded content packages. Supports sponsorship attribution, revenue reporting, and DRM rights enforcement.',
    `category_id` BIGINT COMMENT 'Foreign key linking to content.content_category. Business justification: collection.sport_category is a free-text STRING that duplicates the controlled vocabulary in content_category. Adding content_category_id FK normalizes this to the authoritative content_category refer',
    `fixture_id` BIGINT COMMENT 'Reference to the primary sports or entertainment event (game, match, concert, PPV event) that this collection is associated with. Nullable for evergreen or multi-event collections.',
    `collection_fixture_id` BIGINT COMMENT 'Reference to the primary sports or entertainment event (game, match, concert, PPV event) that this collection is associated with. Nullable for evergreen or multi-event collections.',
    `competition_round_id` BIGINT COMMENT 'Foreign key linking to event.competition_round. Business justification: OTT and broadcast teams curate round-specific content collections (e.g., Quarterfinal Highlights Pack, Round 4 Preview) for distribution. collection has fixture_id and tournament_id but no round-l',
    `facility_id` BIGINT COMMENT 'Foreign key linking to venue.facility. Business justification: Venue-specific content collections (stadium history archives, facility profile packages, naming-rights sponsor content) are curated and licensed as distinct content products tied to a specific physica',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-branded content collections (team highlight reels, franchise season recaps) are a primary content product for team OTT channels and franchise media hubs. Franchise attribution on collections',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Content collections are curated per league (e.g., NFL Season Highlights) for OTT packaging and rights window enforcement. A sports-entertainment domain expert expects collections to be league-scoped',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Collections are explicitly organized by league season (e.g., 2024-25 NBA Regular Season Highlights) for OTT packaging, broadcast rights windows, and archive management. collection.league_season is a',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff bracket content collections (bracket challenge hubs, round-by-round highlight collections, playoff content packages) are curated against specific brackets for OTT and fan engagement platforms.',
    `metadata_tag_id` BIGINT COMMENT 'Foreign key linking to content.metadata_tag. Business justification: A collection is classified under a primary taxonomy tag (e.g., Premier League Highlights, Tennis, Match Day). This FK normalizes the collections primary content classification and gives metadat',
    `rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: Content collections distributed via broadcast have rights_window_start/rights_window_end as denormalized plain attributes. Linking to broadcast_rights_window normalizes this and enables rights teams t',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Branded content collections (e.g., Sponsor X Season Highlights) are created to fulfill specific deal deliverables, not just sponsor relationships. Linking collection to deal enables deal-level conte',
    `segment_id` BIGINT COMMENT 'Foreign key linking to fan.segment. Business justification: Segment-targeted content curation: sports entertainment platforms curate content collections for specific fan segments (e.g., VIP members exclusive, lapsed fans re-engagement). Linking collection ',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Content collections are curated at tournament level (e.g., Champions League 2024 Best Goals). OTT and DAM teams build tournament collections for fan engagement and subscription platforms. league_sea',
    `archived_timestamp` TIMESTAMP COMMENT 'The date and time at which this collection was moved to archived status, removing it from active distribution channels. Supports rights window enforcement and content lifecycle management.',
    `cdn_manifest_url` STRING COMMENT 'The CDN-hosted manifest URL (e.g., HLS/DASH playlist) for streaming delivery of this collection to OTT and digital platforms. Populated upon publication approval.',
    `collection_description` STRING COMMENT 'Long-form editorial description of the collections content, context, and purpose. Displayed on OTT platforms, digital storefronts, and fan engagement interfaces to drive discovery and engagement.',
    `collection_type` STRING COMMENT 'Categorical classification of the collection defining its structural and commercial purpose. [ENUM-REF-CANDIDATE: highlight_reel|playlist|photo_gallery|branded_package|ppv_bundle|editorial_series|audio_album|ugc_compilation — promote to reference product]. Valid values are `highlight_reel|playlist|photo_gallery|branded_package|ppv_bundle|editorial_series`',
    `content_rating` STRING COMMENT 'Audience content rating classification applied to the collection per broadcast and streaming standards (e.g., TV-PG, TV-14). Governs age-gating and parental control enforcement on OTT and digital platforms. [ENUM-REF-CANDIDATE: G|PG|PG-13|R|NR|TV-G|TV-PG|TV-14|TV-MA — 9 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time at which this collection record was first created in the DAM system. Supports audit trail, data lineage, and content lifecycle reporting.',
    `curation_method` STRING COMMENT 'Indicates whether the collection was assembled by human editorial staff, an algorithmic recommendation engine, a hybrid of both, or automated business rules. Drives content governance and quality review workflows.. Valid values are `editorial|algorithmic|hybrid|automated_rules`',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the PPV price (e.g., USD, EUR, GBP). Supports multi-currency pricing for global OTT market distribution.. Valid values are `^[A-Z]{3}$`',
    `dam_collection_code` STRING COMMENT 'Externally-known unique business identifier for the collection as assigned by the Dalet Galaxy DAM system. Used for cross-system reference, API lookups, and CDN manifest identification.. Valid values are `^COL-[A-Z0-9]{6,20}$`',
    `dam_version_number` STRING COMMENT 'Incremental version counter for this collection record as tracked in the Dalet Galaxy DAM system. Supports optimistic concurrency control, change history auditing, and rollback capabilities.',
    `is_featured` BOOLEAN COMMENT 'Indicates whether this collection is designated as a featured or promoted collection on OTT homepages, digital storefronts, or fan engagement platform carousels. Drives editorial merchandising and fan experience design.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this collection is designated as a Pay-Per-View (PPV) content bundle requiring individual purchase or entitlement before access is granted on OTT platforms.',
    `is_ugc` BOOLEAN COMMENT 'Indicates whether this collection contains or is composed of User-Generated Content (UGC) submitted by fans. Triggers additional rights clearance, moderation, and GDPR/CCPA consent validation workflows.',
    `language_code` STRING COMMENT 'ISO 639-1/639-2 language code for the primary language of the collections content (e.g., en, es, fr-CA). Drives localization, subtitle availability, and regional platform routing.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `moderation_status` STRING COMMENT 'Current moderation review state for collections containing UGC or community-sourced content. Ensures brand safety and regulatory compliance before publication on fan-facing platforms.. Valid values are `not_required|pending|approved|rejected|escalated`',
    `ppv_price` DECIMAL(18,2) COMMENT 'Retail price in USD for purchasing access to this PPV collection bundle. Applicable only when is_ppv = true. Used for revenue management, fan entitlement validation, and financial reporting.',
    `primary_content_format` STRING COMMENT 'Dominant media format of assets within the collection. Determines rendering templates, CDN delivery profiles, and platform compatibility requirements.. Valid values are `video|photo|audio|mixed|editorial`',
    `publish_status` STRING COMMENT 'Current lifecycle state of the collection within the content production and distribution workflow. Controls visibility on OTT and digital platforms. [ENUM-REF-CANDIDATE: draft|pending_review|approved|published|scheduled|archived|withdrawn|embargoed — promote to reference product]',
    `published_timestamp` TIMESTAMP COMMENT 'The actual date and time at which this collection was first made publicly available on OTT or digital platforms. Distinct from scheduled_publish_timestamp; records the real-world publication event.',
    `rights_territory_codes` STRING COMMENT 'Pipe-delimited list of ISO 3166-1 alpha-3 country codes defining the geographic territories where this collection is licensed for distribution (e.g., USA|CAN|GBR). Drives geo-blocking and CDN routing logic.',
    `rsn_distribution_flag` BOOLEAN COMMENT 'Indicates whether this collection is cleared for distribution via Regional Sports Networks (RSN). Governs blackout rules and territorial broadcast rights compliance.',
    `scheduled_publish_timestamp` TIMESTAMP COMMENT 'The planned date and time at which this collection is scheduled to be automatically published to OTT and digital platforms. Supports embargo management and coordinated multi-platform release strategies.',
    `seo_keywords` STRING COMMENT 'Comma-separated list of SEO keywords and metadata tags associated with this collection for search discoverability on digital platforms, OTT storefronts, and web search engines.',
    `short_description` STRING COMMENT 'Concise summary (typically 160 characters or fewer) of the collection used for social media previews, push notifications, and mobile platform display cards.',
    `slug` STRING COMMENT 'URL-safe, lowercase hyphenated identifier used for deep-linking and SEO-friendly routing on digital platforms and CDN-delivered pages.. Valid values are `^[a-z0-9]+(?:-[a-z0-9]+)*$`',
    `social_channel_codes` STRING COMMENT 'Pipe-delimited list of social media channel identifiers where this collection is approved for distribution (e.g., YOUTUBE|INSTAGRAM|TIKTOK|TWITTER). Supports social content rights and distribution tracking.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this collection record originated (e.g., Dalet Galaxy DAM, Adobe Experience Platform, manual entry). Supports data lineage and Silver Layer provenance tracking.. Valid values are `DALET_GALAXY|ADOBE_AEP|MANUAL|API_INGEST`',
    `thumbnail_asset_code` STRING COMMENT 'DAM asset code referencing the primary thumbnail or cover image used to represent this collection on OTT platforms, digital storefronts, and social media channels.',
    `title` STRING COMMENT 'Human-readable display title of the collection as it appears on OTT platforms, digital channels, and fan-facing interfaces (e.g., NBA Finals 2024 Highlight Reel, Champions League Photo Gallery).',
    `total_duration_seconds` STRING COMMENT 'Aggregate playback duration of all video and audio assets within the collection, expressed in seconds. Used for OTT platform display, broadcast scheduling, and PPV event bundle packaging.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time at which this collection record was most recently modified. Supports incremental data pipeline processing, change detection, and audit trail requirements.',
    CONSTRAINT pk_collection PRIMARY KEY(`collection_id`)
) COMMENT 'Master entity representing curated groupings of content assets — highlight reels, editorial playlists, photo galleries, branded content packages, and PPV event content bundles. Tracks collection type, member assets with sequence ordering, curation method (editorial vs. algorithmic), publish status, and associated rights window. Supports ordered playlists, highlight packages, and curated galleries for OTT and digital platform delivery.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`license` (
    `license_id` BIGINT COMMENT 'Unique surrogate identifier for each outbound content license or syndication agreement record in the Sports Entertainment content commercialization master.',
    `asset_id` BIGINT COMMENT 'Reference to the specific digital content asset (video highlight, photograph, audio clip, editorial) being licensed, as managed in Dalet Galaxy DAM. Null for collection-level or bulk syndication licenses.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Content licensing administration (rights acquisition, legal, clearance) incurs costs allocated to the licensing department cost center. Sports entertainment finance tracks licensing overhead by cost c',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Long-term broadcast rights licenses (e.g., multi-year league rights deals) are capitalized as intangible fixed assets in SAP Asset Accounting. Finance teams in sports entertainment routinely capitaliz',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Content licenses can be franchise-specific (team channel rights, franchise content packages, local broadcast deals). Franchise-scoped license management is required for territorial rights compliance, ',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Gaming operators license sports highlight clips and live content for display on their sportsbook platforms. Rights management teams issue content licenses specifically to gaming operators; this FK tra',
    `league_id` BIGINT COMMENT 'Reference to the league or competition governing body whose content is being licensed (e.g., NFL, NBA, FIFA Champions League). Populated when content_scope is league, event, or season.',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Content licenses are granted under the authority of a media rights deal (1:N). Rights compliance and revenue recognition teams must reconcile content licenses against their governing media rights deal',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Content licenses are often specific to a distribution platform channel. Linking content_license to platform_channel enables channel-specific license enforcement and reporting.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Content license revenue (syndication fees, royalties, sublicensing) is attributed to profit centers for business unit P&L reporting. Sports entertainment finance tracks licensing revenue streams by pr',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Content licenses for broadcast distribution in regulated markets (FCC, Ofcom, ARPU) must reference the regulatory filing that authorizes the license terms. Sports broadcast rights compliance requires ',
    `revenue_recognition_schedule_id` BIGINT COMMENT 'Foreign key linking to finance.revenue_recognition_schedule. Business justification: Content licenses create performance obligations under ASC 606. Finance creates revenue recognition schedules for multi-period license fees. This link drives the content licensing revenue recognition w',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Content licenses are granted for specific seasons (season-long broadcast rights, season-specific OTT streaming licenses). Season-scoped license tracking is required for rights expiry management, renew',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Content licenses issued as part of sponsorship deal IP rights packages must reference the originating sponsorship deal. Rights teams reconcile content license terms against the sponsorship deals ip_r',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Content licenses in sports entertainment are frequently scoped to specific tournaments (e.g., a broadcaster licenses all content from a specific championship). Rights managers need tournament-scoped l',
    `attribution_required` BOOLEAN COMMENT 'Indicates whether the licensee must display a credit or attribution line (e.g., Courtesy of Sports Entertainment / League Name) when publishing or broadcasting the licensed content. True = attribution mandatory.',
    `attribution_text` STRING COMMENT 'Exact credit line or attribution text the licensee must display when using the licensed content (e.g., Photo: Sports Entertainment / John Smith). Populated when attribution_required is True.',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether the license agreement automatically renews at the end of the effective period without requiring a new negotiation cycle. True = auto-renews; False = requires explicit renewal action.',
    `compliance_status` STRING COMMENT 'Current regulatory and contractual compliance state of the license: compliant (all obligations met), under_review (audit in progress), breach_identified (licensee violation detected), remediated (breach resolved), terminated_for_cause (agreement ended due to material breach). Supports GDPR, CCPA, and IP compliance monitoring.. Valid values are `compliant|under_review|breach_identified|remediated|terminated_for_cause`',
    `content_scope` STRING COMMENT 'Breadth of content covered by the license: single_asset (one specific file), collection (curated package), sport (all content for a sport), league (all content for a league), event (all content for a specific event), season (all content for a competition season). Determines which asset_id or collection_id fields are populated.. Valid values are `single_asset|collection|sport|league|event|season`',
    `contract_document_ref` STRING COMMENT 'Reference identifier or URL to the executed license agreement document stored in the Digital Asset Management (DAM) system or document management repository (e.g., Dalet Galaxy document store, SharePoint). Enables direct access to the legal instrument.',
    `cpm_rate` DECIMAL(18,2) COMMENT 'Monetary rate charged per one thousand impressions (Cost Per Mille) when fee_structure is cpm_based. Used for digital display and OTT advertising-supported license arrangements. Expressed in currency_code.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the license record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail, data lineage, and SOX compliance reporting.',
    `crm_opportunity_reference` STRING COMMENT 'Salesforce CRM Opportunity record identifier associated with the commercial negotiation that resulted in this license. Enables traceability from CRM pipeline to executed license and supports revenue attribution reporting.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which all monetary amounts (flat_fee_amount, royalty_rate, cpm_rate) are denominated (e.g., USD, GBP, EUR). Required for multi-currency international licensing deals.. Valid values are `^[A-Z]{3}$`',
    `dalet_rights_reference` STRING COMMENT 'Dalet Galaxy Digital Asset Management (DAM) system rights record identifier linked to this license. Provides traceability to the source-of-truth rights metadata and DRM policy configuration in the DAM workflow.',
    `deal_type` STRING COMMENT 'Classification of the commercial arrangement: one_off (single asset transaction), syndication (ongoing bulk content feed to media partner), revenue_share (partner monetizes and shares proceeds), broadcast_feed (live or near-live feed to broadcast partner), social_platform (platform partnership for social channel distribution), sublicense (rights passed to a third party). [ENUM-REF-CANDIDATE: one_off|syndication|revenue_share|broadcast_feed|social_platform|sublicense|ppv_window|dtc_exclusive — promote to reference product]. Valid values are `one_off|syndication|revenue_share|broadcast_feed|social_platform|sublicense`',
    `delivery_format` STRING COMMENT 'Technical mechanism by which licensed content is delivered to the licensee: api_feed (Application Programming Interface automated feed), ftp_transfer (file transfer protocol batch), cdn_push (Content Delivery Network push via CDN), manual_download (portal-based manual retrieval), broadcast_signal (OB/satellite signal), email_package (packaged file via email). [ENUM-REF-CANDIDATE: api_feed|ftp_transfer|cdn_push|manual_download|broadcast_signal|email_package|iptv_stream — promote to reference product]. Valid values are `api_feed|ftp_transfer|cdn_push|manual_download|broadcast_signal|email_package`',
    `drm_restrictions` STRING COMMENT 'Free-text description of specific Digital Rights Management technical restrictions applied to the licensed content (e.g., watermarking required, geo-blocking enforced, no download permitted, time-limited playback window). Sourced from Dalet Galaxy DAM rights metadata.',
    `effective_end_date` DATE COMMENT 'Calendar date on which the license agreement expires and content distribution rights are revoked. Null for perpetual or open-ended agreements. Triggers renewal workflow when approaching.',
    `effective_from_date` DATE COMMENT 'Calendar date on which the vendors rights under this license agreement become active and the vendor may begin using the asset. Used for distribution window enforcement and rights scheduling.',
    `effective_start_date` DATE COMMENT 'Calendar date on which the license agreement becomes legally binding and content distribution rights are activated. Aligns with contract execution date or agreed commencement date.',
    `effective_until_date` DATE COMMENT 'Calendar date on which the vendors rights under this license agreement expire. After this date the vendor must cease use of the asset. Triggers automated rights-expiry workflows in the DAM and DRM systems.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this license grants the vendor exclusive rights to the asset within the defined territory_scope. When true, no other vendor may hold a concurrent license for the same asset in the same territory. Critical for rights conflict detection.',
    `expiry_date` DATE COMMENT 'Date on which the assets distribution rights or licence window expires and the asset must be withdrawn from active distribution channels. Critical for DRM (Digital Rights Management) enforcement and rights clearance compliance. [Moved from asset: expiry_date on the asset master conflates the assets overall distribution window with the expiry of individual vendor licenses. A single asset may have licenses expiring on different dates for different vendors. The per-license expiry belongs on content_license.effective_until_date; the asset-level expiry_date should represent the latest possible distribution window across all licenses, not a specific vendors term.]',
    `fee_amount` DECIMAL(18,2) COMMENT 'Agreed monetary consideration paid by the vendor to Sports Entertainment for the rights granted under this license. Expressed in the currency defined by license_fee_currency. Belongs to the license agreement, not to the asset or vendor master.',
    `fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the license_fee_amount is denominated (e.g., USD, GBP, EUR). Required to support multi-currency rights deals with international broadcasters.',
    `fee_structure` STRING COMMENT 'Commercial model governing how the licensee compensates Sports Entertainment: flat_fee (fixed one-time or periodic payment), royalty (per-use or per-unit fee), revenue_share (percentage of licensee revenue), cpm_based (Cost Per Mille impression-based), subscription (periodic access fee), free (no monetary consideration, e.g., promotional or editorial). Drives invoicing logic in SAP S/4HANA SD.. Valid values are `flat_fee|royalty|revenue_share|cpm_based|subscription|free`',
    `feed_frequency` STRING COMMENT 'Cadence at which content is delivered to the licensee under ongoing syndication or broadcast feed arrangements: real_time, hourly, daily, weekly, on_demand (licensee-initiated pull), event_triggered (delivery upon specific event occurrence). Null for one-off licenses.. Valid values are `real_time|hourly|daily|weekly|on_demand|event_triggered`',
    `flat_fee_amount` DECIMAL(18,2) COMMENT 'Fixed monetary amount payable by the licensee for the license term when fee_structure is flat_fee or subscription. Expressed in the currency defined by currency_code. Null for royalty or revenue_share structures.',
    `last_compliance_review_date` DATE COMMENT 'Date on which the most recent compliance audit or review of the license was conducted. Used to schedule periodic compliance checks and track regulatory adherence timelines.',
    `license_name` STRING COMMENT 'Human-readable descriptive name of the license agreement (e.g., ESPN NFL Highlight Syndication 2025, UEFA Champions League Photo License — Getty Images). Used in reporting and partner communications.',
    `license_number` STRING COMMENT 'Externally-known alphanumeric reference code for the license agreement, used in partner correspondence, invoicing, and legal documentation. Format: LIC-{DOMAIN}-{YEAR}-{SEQUENCE}.. Valid values are `^LIC-[A-Z]{2,6}-[0-9]{4}-[0-9]{6}$`',
    `license_scope` STRING COMMENT 'Defines the permitted scope of use for this specific IP asset within the license agreement (e.g., broadcast_only, merchandise, digital_streaming). Scope may differ per IP asset within the same license.',
    `license_status` STRING COMMENT 'Current lifecycle state of the license agreement: draft (being negotiated), active (in force), suspended (temporarily halted due to breach or dispute), expired (past end date without renewal), terminated (cancelled before end date), pending_renewal (auto-renewal under review).. Valid values are `draft|active|suspended|expired|terminated|pending_renewal`',
    `max_usage_count` STRING COMMENT 'Maximum number of times the licensee is permitted to use, broadcast, or distribute the licensed content within the license term. Null indicates unlimited usage. Enables usage cap enforcement and royalty calculation.',
    `payment_frequency` STRING COMMENT 'Cadence at which the licensee is invoiced or remits payment: one_time (single payment), monthly, quarterly, semi_annual, annual. Drives billing schedule generation in SAP S/4HANA SD.. Valid values are `one_time|monthly|quarterly|semi_annual|annual`',
    `renewal_notice_days` STRING COMMENT 'Number of calendar days prior to effective_end_date by which either party must provide written notice of intent not to renew. Drives automated renewal notification workflows.',
    `renewal_term_months` STRING COMMENT 'Duration in months of each automatic renewal cycle. Applicable only when auto_renewal_flag is True. Used to project future effective_end_date upon renewal.',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'Percentage of licensee-generated revenue remitted to Sports Entertainment under a revenue_share fee structure (e.g., 30.00 = 30%). Used in ARPU and ARR revenue forecasting and partner settlement calculations.',
    `rights_territory` STRING COMMENT 'Geographic territory or territories in which the asset is licensed for distribution, expressed as ISO 3166-1 alpha-3 country codes or a named territory group (e.g., USA, GBR, WORLDWIDE, EU_EXCL_UK). Enforced at CDN distribution layer for geo-blocking compliance. [Moved from asset: rights_territory on the asset master represents a default or aggregate territory, but the actual licensed territory is specific to each vendor-asset license agreement. When the same asset is licensed to multiple vendors across different territories, a single rights_territory field on the asset cannot represent all concurrent license scopes. The per-license territory belongs on content_license.territory_scope.]',
    `royalty_rate` DECIMAL(18,2) COMMENT 'Per-use or per-unit royalty rate expressed as a decimal (e.g., 0.0500 = 5%). Applicable when fee_structure is royalty. Used to calculate royalty invoices based on reported usage volumes.',
    `signed_date` DATE COMMENT 'Date on which all parties executed the license agreement. May differ from effective_start_date when agreements are backdated or have a future commencement.',
    `sport_code` STRING COMMENT 'Standardized code identifying the sport associated with the licensed content (e.g., NFL, NBA, MLB, NHL, MLS, FIFA, UFC, ATP). Populated when content_scope is sport, league, event, or season. Enables sport-level rights analytics.',
    `sublicense_permitted` BOOLEAN COMMENT 'Indicates whether the licensee is contractually permitted to sublicense the content to third parties. True = sublicensing allowed (subject to conditions); False = sublicensing prohibited. Critical for IP chain-of-title integrity.',
    `territory_exclusivity` STRING COMMENT 'Defines whether the licensee holds exclusive rights in the specified territory (exclusive), shares rights with other licensees (non_exclusive), or holds first-window broadcast priority before other licensees (first_window). Directly impacts RSN and OTT deal structuring.. Valid values are `exclusive|non_exclusive|first_window`',
    `ugc_rights_included` BOOLEAN COMMENT 'Indicates whether the license grants the licensee rights to use or incorporate User-Generated Content (UGC) associated with the licensed assets (e.g., fan footage, social clips). True = UGC rights included; False = excluded.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the license record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change tracking, incremental data pipeline processing, and audit compliance.',
    `usage_rights_granted` STRING COMMENT 'Classification of the media usage rights conveyed to the vendor under this license agreement. Determines which distribution channels and use cases the vendor is permitted to exercise.',
    `usage_type` STRING COMMENT 'Permitted exploitation category for the licensed content: broadcast (linear TV/radio), streaming_ott (Over-The-Top Streaming platforms), social_media (social channel posting), editorial (news/journalism), commercial (advertising/promotional), print (physical/digital publication), digital_display (website/app display). [ENUM-REF-CANDIDATE: broadcast|streaming_ott|social_media|editorial|commercial|print|digital_display|ppv|dtc|iptv — promote to reference product]',
    `watermark_required` BOOLEAN COMMENT 'Indicates whether the licensee is contractually required to apply a visible or forensic watermark to distributed content for IP tracking and anti-piracy enforcement. True = watermark mandatory; False = not required.',
    CONSTRAINT pk_license PRIMARY KEY(`license_id`)
) COMMENT 'Master record for all outbound content commercialization agreements — covering individual asset licenses, bulk syndication deals (ongoing content feeds to media partners), third-party media outlet arrangements, social platform partnerships, broadcast partner feeds, and commercial licensees. Captures licensee/partner identity, licensed scope (asset, collection, sport, league), deal type (one-off license, ongoing syndication, revenue-share partnership), territory, usage type, fee structure (flat fee, royalty, revenue share), delivery format and schedule, content feed frequency, start/end dates, auto-renewal terms, and compliance status. SSOT for all outbound content monetization distinct from inbound rights_clearance.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`editorial_brief` (
    `editorial_brief_id` BIGINT COMMENT 'Unique system-generated identifier for the editorial brief record. Primary key for the editorial_brief data product within the content domain.',
    `bracket_id` BIGINT COMMENT 'Foreign key linking to event.bracket. Business justification: Bracket draw editorial briefs and bracket analysis pieces (draw reaction, path-to-final analysis) are commissioned against specific brackets. editorial_brief has tournament_id but not bracket_id; brac',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to fan.campaign. Business justification: Campaign-driven content commissioning: editorial briefs in sports entertainment are frequently initiated by a marketing campaign (e.g., campaign requires a player profile, match preview, or sponsor fe',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: Editorial briefs are commissioned for specific broadcast channels whose programming requirements (format, duration, language, resolution) drive the briefs specifications. Programming and editorial te',
    `competition_round_id` BIGINT COMMENT 'Foreign key linking to event.competition_round. Business justification: Editorial briefs are commissioned per competition round (round preview, round review, tactical analysis). editorial_brief has fixture_id and tournament_id but no round-level FK; round-level editorial ',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Editorial briefs for branded content, NIL features, or sensitive topics reference compliance policies (editorial standards, branded content policy). The editorial_brief has content_sensitivity_level a',
    `contest_id` BIGINT COMMENT 'Foreign key linking to gaming.contest. Business justification: Editorial teams commission DFS slate preview articles, contest strategy guides, and lineup advice content tied to specific gaming contests. This is a named content workflow in sports-entertainment (di',
    `asset_id` BIGINT COMMENT 'Reference identifier of the associated digital asset record in the Dalet Galaxy DAM (Digital Asset Management) system. Links the editorial brief to the master content asset record for rights, metadata, and distribution management.',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Sponsored content briefs are commissioned to fulfill specific deal obligations (e.g., contracted branded content pieces). Linking brief to deal enables deal fulfillment tracking, compliance auditing o',
    `disciplinary_action_id` BIGINT COMMENT 'Foreign key linking to league.disciplinary_action. Business justification: Disciplinary actions (suspensions, fines, integrity rulings) generate immediate editorial briefs for news coverage, official statements, and investigative features. Sports journalists and content team',
    `facility_id` BIGINT COMMENT 'Foreign key linking to venue.facility. Business justification: Editorial briefs for naming rights activations, facility feature stories, and in-venue digital content campaigns are scoped to a specific facility. Facility-scoped editorial planning is a real named b',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Editorial briefs are commissioned for franchise-specific content (team features, franchise anniversary documentaries, locker-room access stories). Franchise-scoped editorial commissioning drives conte',
    `league_id` BIGINT COMMENT 'Identifier of the professional league or governing competition body that is the primary context for this editorial brief. Links to the league master record.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Editorial briefs are commissioned for specific league seasons (season previews, playoff coverage, end-of-season reviews). editorial_brief.season_year is a plain-text denormalization — replaced by FK t',
    `match_result_id` BIGINT COMMENT 'Foreign key linking to event.match_result. Business justification: Post-match editorial briefs (match reports, player ratings, tactical analysis) are commissioned upon result confirmation. editorial_brief has fixture_id but not match_result_id; result confirmation is',
    `athlete_profile_id` BIGINT COMMENT 'Identifier of the primary athlete or talent featured in the editorial brief. Nullable for team-focused or event-focused content. Links to the athlete master record.',
    `fixture_id` BIGINT COMMENT 'Identifier of the specific sporting event, match, or live experience that is the primary subject of this editorial brief. Nullable for non-event-specific editorial content.',
    `production_order_id` BIGINT COMMENT 'Identifier of the associated content production order that operationalises this editorial brief. Links the brief to the production workflow, resource allocation, and cost tracking.',
    `production_schedule_id` BIGINT COMMENT 'Foreign key linking to event.production_schedule. Business justification: Event production schedules (halftime shows, pre-show segments) commission editorial briefs for scripted content, presenter notes, and segment rundowns. editorial_brief has fixture_id but not productio',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to merchandise.promotion. Business justification: Merchandise promotions (jersey launches, limited editions) trigger editorial briefs for social/digital content production. Content teams track which merchandise promotion each brief supports for campa',
    `security_incident_id` BIGINT COMMENT 'Foreign key linking to security.security_incident. Business justification: Editorial briefs are routinely commissioned to cover stadium security incidents as news stories. Sports content teams need this link to track which briefs were triggered by specific incidents, support',
    `sponsor_id` BIGINT COMMENT 'Identifier of the commercial sponsor associated with this editorial brief, where content is produced as part of a sponsored content or branded content arrangement. Nullable for non-sponsored editorial.',
    `segment_id` BIGINT COMMENT 'Foreign key linking to fan.segment. Business justification: Segment-driven content commissioning: editorial briefs in sports entertainment are commissioned to address specific fan segments (e.g., create re-engagement content for churned subscribers). Linking',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Editorial briefs are commissioned at tournament level for tournament preview/review packages, documentary content, and long-form editorial. Editors need tournament-level brief tracking for editorial c',
    `trade_transaction_id` BIGINT COMMENT 'Foreign key linking to league.trade_transaction. Business justification: Trade announcements are among the highest-traffic editorial events in sports media. Editorial briefs for trade coverage (breaking news, analysis, press conference scheduling) are directly triggered by',
    `approval_status` STRING COMMENT 'Current state of the editorial approval workflow for this brief. Tracks progression through editorial review, legal clearance, and final sign-off stages before publication.. Valid values are `pending|under_review|approved|rejected|revision_requested`',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the editorial brief and associated content received final editorial approval. Null if not yet approved. Used for SLA (Service Level Agreement) compliance measurement.',
    `branded_content_flag` BOOLEAN COMMENT 'Indicates whether this editorial brief is for branded or sponsored content that requires commercial disclosure labelling per FCC and advertising standards. Triggers compliance review workflow.',
    `brief_reference_code` STRING COMMENT 'Externally-known alphanumeric code used to identify and reference the editorial brief across production systems, editorial calendars, and commissioning workflows. Format: EB-{SPORT}-{YEAR}-{SEQUENCE}.. Valid values are `^EB-[A-Z]{2,6}-[0-9]{4}-[0-9]{5}$`',
    `brief_status` STRING COMMENT 'Current lifecycle state of the editorial brief within the content production pipeline, from initial commissioning through publication or cancellation. [ENUM-REF-CANDIDATE: draft|commissioned|in_production|under_review|approved|published|cancelled — promote to reference product]',
    `brief_title` STRING COMMENT 'Human-readable working title of the editorial brief, describing the story or content piece being commissioned. Used in editorial calendars and production dashboards.',
    `cancellation_reason` STRING COMMENT 'Free-text explanation of why the editorial brief was cancelled, if applicable. Null for active or completed briefs. Used for editorial pipeline analysis and resource recovery tracking.',
    `commissioned_timestamp` TIMESTAMP COMMENT 'Date and time when the editorial brief was formally commissioned and entered the production pipeline. Represents the principal business event timestamp for this transaction.',
    `content_priority` STRING COMMENT 'Editorial priority level assigned to this brief, determining resource allocation, production queue position, and escalation thresholds. Breaking news content receives highest priority.. Valid values are `breaking|high|standard|low`',
    `content_sensitivity_level` STRING COMMENT 'Classification of the editorial contents sensitivity level, determining access controls, legal review requirements, and distribution restrictions. Sensitive content (e.g., PED allegations, CBA disputes) requires legal sign-off.. Valid values are `standard|sensitive|legally_restricted|embargoed`',
    `content_type` STRING COMMENT 'Classification of the content format being produced under this brief. Determines production workflow, asset requirements, and distribution channel eligibility. [ENUM-REF-CANDIDATE: article|video_highlight|photo_gallery|podcast|social_post|long_form|match_report|infographic|live_blog — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the editorial brief record was first created in the system. Used for audit trail and data lineage tracking.',
    `drm_rights_status` STRING COMMENT 'Status of digital rights clearance for the content covered by this editorial brief. Governs whether the content can be distributed across target platforms. DRM (Digital Rights Management) clearance is mandatory before publication.. Valid values are `cleared|pending_clearance|restricted|not_required|expired`',
    `duration_target_seconds` STRING COMMENT 'Target runtime duration in seconds for audio-visual content (video highlights, podcasts, broadcast segments). Null for text-based content types. Drives production scheduling and CDN (Content Delivery Network) capacity planning.',
    `embargo_timestamp` TIMESTAMP COMMENT 'Date and time before which the content must not be published or distributed. Used for coordinated release of exclusive stories, pre-match previews, and league-mandated embargo windows.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether the editorial content is designated as exclusive to the commissioning platform or outlet. Exclusive content carries higher production priority and stricter embargo controls.',
    `language_code` STRING COMMENT 'IETF BCP 47 language tag specifying the primary language in which the content is to be produced (e.g., en-US, es-ES, fr-FR). Drives localisation workflows and multi-market distribution.. Valid values are `^[a-z]{2}-[A-Z]{2}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when the editorial brief record was most recently updated. Used for change tracking, cache invalidation, and audit compliance.',
    `notes` STRING COMMENT 'Free-text field for additional editorial guidance, special instructions, contextual background, or production notes provided by the commissioning editor to the assigned journalist or producer.',
    `publication_deadline` TIMESTAMP COMMENT 'Target date and time by which the content must be published or broadcast. May differ from submission deadline to allow for editorial review, legal clearance, and CDN distribution lead time.',
    `published_timestamp` TIMESTAMP COMMENT 'Date and time when the content produced under this brief was formally published or broadcast. Null if not yet published. Used for SLA (Service Level Agreement) compliance and editorial performance reporting.',
    `revision_count` STRING COMMENT 'Number of revision cycles the editorial brief has undergone since initial commissioning. Tracks editorial iteration and is used to identify briefs requiring excessive rework for process improvement.',
    `rights_territory` STRING COMMENT 'Geographic territory or market for which content distribution rights have been cleared. Expressed as ISO 3166-1 alpha-3 country codes or regional groupings. Drives geo-restricted CDN (Content Delivery Network) distribution rules.',
    `seo_keywords` STRING COMMENT 'Comma-separated list of target keywords and search terms to be incorporated into the content for digital discoverability. Supports DTC (Direct-To-Consumer) audience acquisition strategy.',
    `social_channel_target` STRING COMMENT 'Specific social media platform(s) targeted for distribution of content produced under this brief (e.g., Instagram, X/Twitter, TikTok, YouTube). Drives format and duration specifications for social-first content.',
    `sport_discipline` STRING COMMENT 'The sport or athletic discipline that is the primary subject of the editorial brief (e.g., football, basketball, tennis, mixed martial arts). Aligns with league and competition governance taxonomy.',
    `story_angle` STRING COMMENT 'Narrative perspective, editorial angle, or thematic focus of the content piece. Describes the unique hook or framing that differentiates this story from standard match or event coverage.',
    `submission_deadline` TIMESTAMP COMMENT 'Date and time by which the assigned journalist or producer must submit the completed content for editorial review. Critical for time-sensitive sports news and live event coverage.',
    `ugc_sourced_flag` BOOLEAN COMMENT 'Indicates whether this editorial brief incorporates or is based on UGC (User Generated Content) sourced from fan platforms or social channels. Triggers additional rights clearance and GDPR compliance workflows.',
    `word_count_target` STRING COMMENT 'Target word count for written editorial content (articles, long-form, match reports). Null for non-text content types such as video or photo galleries. Used for editorial planning and writer briefing.',
    CONSTRAINT pk_editorial_brief PRIMARY KEY(`editorial_brief_id`)
) COMMENT 'Master record for editorial content briefs — capturing story angle, assigned journalist or producer, target platform, sport/league/event context, word count or duration target, deadline, approval workflow status, and associated production order. Governs the editorial content production pipeline from commissioning to publication.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`platform_channel` (
    `platform_channel_id` BIGINT COMMENT 'Unique surrogate identifier for each distribution platform channel record in the content domain. Primary key for the platform_channel reference master.',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Platform channels must operate under broadcast standards and content policies (age rating policy, geo-restriction policy, closed captioning policy). The channel has content_rating_system and drm_requi',
    `category_id` BIGINT COMMENT 'Foreign key linking to content.content_category. Business justification: platform_channel.content_category is a free-text STRING column that should reference the authoritative content_category master. Adding content_category_id FK enforces referential integrity and ensures',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Platform channels (OTT, broadcast, social) have ongoing operating costs (CDN, streaming infrastructure, staffing) allocated to departmental cost centers. Sports entertainment finance tracks channel op',
    `channel_id` BIGINT COMMENT 'The native channel identifier assigned to this distribution channel within the Dalet Galaxy Media Asset Management (MAM) and broadcast workflow system. Used to correlate platform_channel records with Dalet Galaxy publish destination configurations and workflow routing rules. System-of-record cross-reference key.',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Platform channels are licensed to distribute specific league content (league-branded OTT apps, RSN league packages, league pass channels). League-channel distribution agreements are a core business re',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: A platform channel (OTT, IPTV) operates under a governing media rights deal that defines distributable content, territory scope, and exclusivity terms. Platform channel setup, rights compliance, and s',
    `operator_id` BIGINT COMMENT 'Foreign key linking to gaming.operator. Business justification: Sportsbook-branded streaming channels (e.g., FanDuel TV, ESPN Bet integrations) are operated by or affiliated with a licensed gaming operator. Content distribution teams must track which gaming operat',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Platform channels are distinct revenue-generating business units tracked as profit centers (e.g., OTT platform P&L, broadcast channel P&L). Sports entertainment finance requires channel-level profitab',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Platform channels operating as broadcast or OTT services in regulated markets hold regulatory licenses (FCC broadcast license, Ofcom license). Compliance teams must link each channel to its operating ',
    `ad_insertion_enabled` BOOLEAN COMMENT 'Indicates whether dynamic ad insertion (DAI) or server-side ad insertion (SSAI) is enabled for content delivered on this platform channel. True = ad markers and SCTE-35 cue points must be included in the content package; False = ad-free delivery. Relevant for CPM-based revenue channels and sponsor integration.',
    `api_endpoint_url` STRING COMMENT 'The Application Programming Interface (API) endpoint URL for programmatic content submission and metadata exchange with this platform channels operator system. Classified as confidential as it represents proprietary integration infrastructure. Used for automated publish event routing from Dalet Galaxy.. Valid values are `^https?://[^s/$.?#].[^s]*$`',
    `audio_format` STRING COMMENT 'Audio format specification required or supported by this platform channel for content delivery. Drives audio encoding and packaging decisions in Dalet Galaxy production workflows. stereo = standard 2-channel; 5_1_surround = 5.1 surround sound; 7_1_surround = 7.1 surround sound; dolby_atmos = immersive Dolby Atmos; mono = single channel.. Valid values are `stereo|5_1_surround|7_1_surround|dolby_atmos|mono`',
    `cdn_endpoint_url` STRING COMMENT 'The CDN ingest or origin endpoint URL for delivering content to this platform channel. Classified as confidential as it represents proprietary infrastructure routing information. Used by Dalet Galaxy automated publish workflows to push packaged content to the correct CDN origin.. Valid values are `^https?://[^s/$.?#].[^s]*$`',
    `cdn_provider` STRING COMMENT 'Name of the Content Delivery Network (CDN) provider used to distribute content to this platform channel (e.g., Akamai, Fastly, Cloudflare, AWS CloudFront, Limelight). Determines the CDN endpoint configuration and SLA parameters for content delivery performance.',
    `channel_code` STRING COMMENT 'Externally-known unique business code identifying the distribution channel (e.g., ESPN_OTT_US, RSN_BALLY_MIDWEST, PPV_UFC_GLOBAL). Used as the canonical business identifier in Dalet Galaxy DAM publish routing and CDN distribution configurations.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `channel_name` STRING COMMENT 'Human-readable display name of the distribution platform channel (e.g., ESPN+ OTT United States, Bally Sports Midwest RSN, UFC PPV Global Portal). Used in reporting, content routing dashboards, and rights management interfaces.',
    `channel_status` STRING COMMENT 'Current operational lifecycle status of the platform channel. Active channels are eligible to receive publish events and content routing. Suspended channels are temporarily blocked from receiving new content. Decommissioned channels are retired from distribution operations.. Valid values are `active|inactive|suspended|pending_launch|decommissioned`',
    `channel_type` STRING COMMENT 'Classification of the distribution channel by delivery technology and business model. OTT = Over-The-Top streaming app; RSN = Regional Sports Network; PPV = Pay-Per-View portal; IPTV = Internet Protocol Television; DTC = Direct-To-Consumer streaming; social_media = social platform channel; linear_broadcast = traditional broadcast slot. Drives rights window routing and DRM policy selection. [ENUM-REF-CANDIDATE: OTT|RSN|PPV|IPTV|DTC|social_media|linear_broadcast — 7 candidates stripped; promote to reference product]',
    `channel_url` STRING COMMENT 'The public-facing URL of the platform channel accessible to end consumers (e.g., the OTT app store URL, the social media channel page URL, the DTC streaming portal URL). Used for fan engagement linking, marketing campaigns, and digital platform analytics in Adobe Experience Platform.. Valid values are `^https?://[^s/$.?#].[^s]*$`',
    `closed_captioning_required` BOOLEAN COMMENT 'Indicates whether closed captioning (CC) is mandatory for all content published to this platform channel. True = closed captions must be included in the content package per ADA or FCC accessibility requirements; False = optional. Drives caption generation and QC steps in the Dalet Galaxy publish workflow.',
    `concurrent_stream_limit` STRING COMMENT 'Maximum number of simultaneous content streams permitted on this platform channel at any given time, as defined in the operator SLA or broadcast rights agreement. Used for capacity planning, CDN bandwidth provisioning, and SLA compliance monitoring.',
    `content_rating_system` STRING COMMENT 'The content rating classification system applicable to this platform channels territory and regulatory environment (e.g., MPAA for US theatrical, TV Parental Guidelines for US broadcast, BBFC for UK, FSK for Germany). Determines which content rating metadata must be included in publish packages and enforced at the channel level.. Valid values are `MPAA|TV_Parental_Guidelines|BBFC|FSK|PEGI|none`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this platform channel record was first created in the content domain master data registry. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for audit trail, data lineage, and SOX compliance reporting.',
    `decommission_date` DATE COMMENT 'The date on which this platform channel was or is scheduled to be decommissioned and removed from active content distribution. Nullable for active channels. Used to enforce rights window expiry and cease automated publish routing to retired endpoints.',
    `drm_required` BOOLEAN COMMENT 'Indicates whether Digital Rights Management (DRM) encryption is mandatory for all content published to this platform channel. True = DRM packaging required before delivery; False = unencrypted delivery permitted (e.g., free-to-air social channels). Used as a gate in the Dalet Galaxy publish workflow.',
    `drm_system` STRING COMMENT 'The Digital Rights Management (DRM) technology required by this platform channel for content protection and access control. Widevine is used for Android/Chrome; FairPlay for Apple devices; PlayReady for Microsoft/Smart TVs; multi_drm indicates the channel supports multiple DRM systems simultaneously. Drives DRM packaging decisions in Dalet Galaxy and CDN delivery configurations.. Valid values are `Widevine|FairPlay|PlayReady|ClearKey|multi_drm|none`',
    `geo_restriction_enabled` BOOLEAN COMMENT 'Indicates whether geographic (geo-blocking) restrictions are enforced for content delivered to this platform channel. True = CDN geo-restriction rules are applied based on territory_code; False = global delivery without geo-blocking. Critical for broadcast rights compliance and territorial exclusivity enforcement.',
    `hdr_supported` BOOLEAN COMMENT 'Indicates whether this platform channel supports High Dynamic Range (HDR) video delivery. True = HDR content (HDR10, Dolby Vision, HLG) can be delivered to this channel; False = SDR only. Drives HDR transcoding and packaging decisions in the content production workflow.',
    `language_code` STRING COMMENT 'ISO 639-1 or ISO 639-2 language code representing the primary language of content delivered on this platform channel (e.g., en, es, fr, pt-BR). Used for content localization routing, subtitle/dubbing requirements, and regional audience targeting in Adobe Experience Platform.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `launch_date` DATE COMMENT 'The date on which this platform channel became operational and began accepting content distribution. Used to calculate channel tenure, validate rights window effective dates, and support historical analytics on channel performance.',
    `live_streaming_enabled` BOOLEAN COMMENT 'Indicates whether this platform channel is configured and authorized to receive and distribute live streaming content (e.g., live game broadcasts, live PPV events). True = live streaming supported; False = VOD/on-demand only. Critical for live event publish routing decisions.',
    `max_resolution` STRING COMMENT 'Maximum video resolution supported by this platform channel for content delivery. SD = Standard Definition (480p); HD = High Definition (720p); FHD = Full High Definition (1080p); UHD_4K = Ultra High Definition 4K (2160p); UHD_8K = Ultra High Definition 8K (4320p). Used to determine transcoding profiles in Dalet Galaxy and CDN packaging.. Valid values are `SD|HD|FHD|UHD_4K|UHD_8K`',
    `metadata_standard` STRING COMMENT 'The metadata schema standard required by this platform channel for content package delivery (e.g., EIDR for entertainment identifier registry, EBUCore for broadcast, Dublin Core for general digital assets, IPTC for news/sports photography). Drives metadata mapping and transformation in Dalet Galaxy export workflows.. Valid values are `EIDR|EBUCore|Dublin_Core|IPTC|custom`',
    `ppv_enabled` BOOLEAN COMMENT 'Indicates whether this platform channel is configured to support Pay-Per-View (PPV) transactional content purchases. True = PPV events can be routed to this channel with associated purchase gating; False = subscription or free-to-air only. Drives PPV event publish routing and revenue management integration.',
    `publish_lead_time_minutes` STRING COMMENT 'Minimum number of minutes required before a scheduled broadcast or rights window start time that content must be submitted to this platform channel for successful ingestion and processing. Used by Dalet Galaxy automated scheduling to trigger publish events with sufficient lead time.',
    `rights_window_default_days` STRING COMMENT 'Default number of days that content rights are valid for distribution on this platform channel, used as a baseline when no specific rights agreement overrides are present. Supports automated rights window calculation in the Dalet Galaxy DRM and rights clearance workflow.',
    `sla_uptime_target_pct` DECIMAL(18,2) COMMENT 'The contractually agreed Service Level Agreement (SLA) uptime target percentage for this platform channel, expressed as a percentage (e.g., 99.90 = 99.9% uptime). Used for CDN performance monitoring, operator SLA compliance reporting, and penalty clause evaluation.',
    `social_handle` STRING COMMENT 'The official social media handle or username for this platform channel (e.g., @NBASports, @PremierLeague). Applicable for social_media channel types. Used for content routing, fan engagement tracking, and UGC attribution in Adobe Experience Platform and social analytics.',
    `subscription_model` STRING COMMENT 'Business model governing how consumers access content on this platform channel. free = no cost access; subscription = recurring subscription fee (ARR/ARPU driven); ppv = Pay-Per-View (PPV) transactional; freemium = free tier with premium upgrade; ad_supported = free with advertising (CPM-based revenue). Informs rights window configuration and revenue attribution.. Valid values are `free|subscription|ppv|freemium|ad_supported`',
    `supported_content_formats` STRING COMMENT 'Comma-separated list of content asset formats accepted by this platform channel (e.g., MP4,HLS,DASH,MXF,HEVC). Defines the technical delivery specifications required when routing publish events from Dalet Galaxy to this channel endpoint. [ENUM-REF-CANDIDATE: MP4|HLS|DASH|MXF|HEVC|H264|H265|ProRes|AAC|MP3|JPEG|PNG|WebM — promote to reference product]',
    `ugc_accepted` BOOLEAN COMMENT 'Indicates whether this platform channel accepts and distributes User-Generated Content (UGC) from fans and community contributors. True = UGC assets can be routed to this channel after rights clearance; False = professionally produced content only. Relevant for social media channels and fan engagement platforms managed via Adobe Experience Platform.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this platform channel record was most recently modified. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC), data lineage tracking, and audit compliance in the Databricks Silver Layer.',
    `vod_enabled` BOOLEAN COMMENT 'Indicates whether this platform channel supports Video On Demand (VOD) content delivery. True = VOD content (highlights, replays, documentaries) can be published to this channel; False = live-only channel. Used in content routing logic to determine eligible publish targets.',
    `watermarking_required` BOOLEAN COMMENT 'Indicates whether forensic or visible watermarking is required for content delivered to this platform channel to enable piracy detection and source identification. True = watermarking must be applied during packaging in Dalet Galaxy; False = no watermarking required. Supports IP protection and anti-piracy compliance.',
    CONSTRAINT pk_platform_channel PRIMARY KEY(`platform_channel_id`)
) COMMENT 'Reference master for all distribution platform channels — OTT apps, RSN broadcast slots, social media channels, DTC streaming, IPTV, and PPV portals. Captures platform name, channel type, operator, territory, supported content formats, and DRM requirements. Used to route publish events and rights windows to the correct distribution endpoint.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`category` (
    `category_id` BIGINT COMMENT 'Primary key for content_category',
    `parent_category_id` BIGINT COMMENT 'Reference to parent content category for hierarchical taxonomy structure. Null for top-level categories. Enables multi-level content classification trees.',
    `parent_content_category_id` BIGINT COMMENT 'Self-referencing FK on content_category (parent_content_category_id)',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Content categories (e.g., Gambling-Adjacent, Adult, Athlete Personal) are governed by specific compliance policies determining age rating requirements, geo-restrictions, and approval workflows. The co',
    `age_rating_required` BOOLEAN COMMENT 'Indicates whether content in this category must be assigned an age rating classification (e.g., G, PG, PG-13, R) for audience suitability and parental guidance.',
    `allowed_file_formats` STRING COMMENT 'Comma-separated list of permitted file format extensions for content assets in this category (e.g., mp4, mov, jpg, png, mp3). Enforced during content ingestion workflows.',
    `analytics_tracking_enabled` BOOLEAN COMMENT 'Indicates whether detailed user engagement analytics and viewing metrics are collected for content in this category for performance analysis and content optimization.',
    `archive_priority` STRING COMMENT 'Priority classification for archival processing when content reaches end of active lifecycle. Immediate priority content is archived within 24 hours; deferred may wait up to 90 days.',
    `category_code` STRING COMMENT 'Short alphanumeric code representing the content category for system integration and API usage. Used as business identifier across digital asset management systems.',
    `category_description` STRING COMMENT 'Detailed description of the content category explaining its purpose, scope, and usage guidelines for content producers and editors.',
    `category_level` STRING COMMENT 'Numeric level in the category hierarchy tree where 1 represents top-level categories and higher numbers represent deeper nesting. Used for taxonomy navigation and filtering.',
    `category_name` STRING COMMENT 'Human-readable name of the content category displayed in user interfaces and content management systems.',
    `category_type` STRING COMMENT 'Primary media type classification for this category indicating the dominant content format (video highlights, photography, audio clips, documents, social media assets, or user-generated content).',
    `cdn_distribution_tier` STRING COMMENT 'Distribution priority tier for content delivery network (CDN) caching and edge delivery strategy. Premium tier receives highest bandwidth allocation and global edge presence.',
    `content_category_status` STRING COMMENT 'Current lifecycle status of the content category indicating whether it is available for content tagging and classification workflows.',
    `created_by_user` STRING COMMENT 'Username or user identifier of the person who created this content category record. Used for accountability and audit purposes.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this content category record was first created in the system. Used for audit trail and data lineage tracking.',
    `default_retention_days` STRING COMMENT 'Standard number of days that content assets in this category are retained in active storage before archival or deletion per content lifecycle management policy.',
    `display_order` STRING COMMENT 'Numeric value controlling the presentation sequence of categories in user interfaces, content management systems, and API responses. Lower values appear first.',
    `effective_end_date` DATE COMMENT 'Date when this content category was retired or deprecated and is no longer available for new content tagging. Null for currently active categories.',
    `effective_start_date` DATE COMMENT 'Date when this content category became active and available for content classification and tagging workflows. Used for temporal validity tracking.',
    `geo_restriction_enabled` BOOLEAN COMMENT 'Indicates whether content in this category is subject to geographic distribution restrictions based on licensing agreements and territorial rights.',
    `is_rights_sensitive` BOOLEAN COMMENT 'Flag indicating whether content in this category requires special digital rights management (DRM) clearance and licensing review before distribution.',
    `is_searchable` BOOLEAN COMMENT 'Indicates whether this category is exposed in public-facing search interfaces and content discovery features on digital platforms and mobile applications.',
    `is_user_selectable` BOOLEAN COMMENT 'Indicates whether end users can select this category when uploading user-generated content (UGC) or filtering content in fan engagement platforms.',
    `max_file_size_mb` DECIMAL(18,2) COMMENT 'Maximum allowed file size in megabytes for content assets in this category. Used for upload validation and storage capacity planning.',
    `metadata_schema_version` STRING COMMENT 'Version identifier of the metadata schema template applied to content assets in this category within Dalet Galaxy DAM system. Format: major.minor.patch (e.g., 2.1.0).',
    `modified_by_user` STRING COMMENT 'Username or user identifier of the person who last modified this content category record. Used for change accountability and audit trail.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this content category record was last modified. Updated whenever any attribute value changes. Used for change tracking and synchronization.',
    `monetization_eligible` BOOLEAN COMMENT 'Indicates whether content in this category is eligible for monetization through advertising, sponsorships, pay-per-view, or subscription revenue models.',
    `notes` STRING COMMENT 'Free-form text field for additional notes, usage guidelines, or special instructions related to this content category for content producers and editors.',
    `requires_approval` BOOLEAN COMMENT 'Indicates whether content tagged with this category must undergo editorial or compliance approval workflow before publication to digital platforms or social channels.',
    `seo_priority` STRING COMMENT 'Priority level for search engine optimization efforts and metadata enrichment for content in this category to maximize organic discovery and traffic.',
    `social_sharing_enabled` BOOLEAN COMMENT 'Indicates whether content in this category can be shared by users on social media platforms through embedded sharing widgets and social integration features.',
    `target_platforms` STRING COMMENT 'Comma-separated list of intended distribution platforms for this content category (e.g., OTT, mobile app, social media, broadcast, website). Guides content production and format specifications.',
    `thumbnail_required` BOOLEAN COMMENT 'Indicates whether automatic thumbnail image generation is required for content assets in this category for preview and navigation purposes in content management interfaces.',
    `watermark_required` BOOLEAN COMMENT 'Indicates whether digital watermarking must be applied to content assets in this category for brand protection and unauthorized distribution prevention.',
    CONSTRAINT pk_category PRIMARY KEY(`category_id`)
) COMMENT 'Master reference table for content_category. Referenced by content_category_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`collection_item` (
    `collection_item_id` BIGINT COMMENT 'Primary key for the collection_item association',
    `asset_id` BIGINT COMMENT 'Foreign key linking to the digital content asset that is a member of the collection.',
    `collection_id` BIGINT COMMENT 'Foreign key linking to the parent content collection that contains this asset membership record.',
    `added_by_user` STRING COMMENT 'Identifier or username of the editorial staff member or system process that added this asset to the collection. Captures the operational provenance of the membership record.',
    `added_timestamp` TIMESTAMP COMMENT 'Date and time when this asset was added to the collection by an editorial user or automated curation process. Belongs to the membership event, not to the asset or collection independently.',
    `is_featured_in_collection` BOOLEAN COMMENT 'Indicates whether this asset is designated as a featured or promoted item within this specific collection. A single asset may be featured in one collection but not another, making this a relationship-level attribute.',
    `position_in_collection` BIGINT COMMENT 'Ordinal position of the asset within the collection sequence. Drives playback order for playlists and display order for galleries. Belongs to the membership relationship, not to the asset or collection independently.',
    CONSTRAINT pk_collection_item PRIMARY KEY(`collection_item_id`)
) COMMENT 'This association product represents the membership relationship between a content collection and a digital asset in the Dalet Galaxy DAM. It captures the operational fact that a specific asset has been curated into a specific collection, including its position in the sequence, when it was added, who added it, and whether it is featured within that collection. Each record links one collection to one asset with attributes that exist only in the context of this membership relationship — not on the collection or asset alone.. Existence Justification: In DAM (Digital Asset Management) operations for sports entertainment, a content collection is explicitly defined as a curated grouping of multiple assets (highlight reels, playlists, galleries), and any single asset (a video clip, photo, article) can appear in multiple collections simultaneously — e.g., a LeBron James dunk clip may appear in a Top 10 Plays collection, a Lakers Season Highlights collection, and a PPV Event Bundle. This is a foundational operational relationship in Dalet Galaxy DAM, where collection membership is actively managed by editorial staff with ordering, featured flags, and timestamps. The relationship is a recognized business entity (collection membership or collection item) that humans create, reorder, feature, and remove as part of daily content operations.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`content`.`asset_tag` (
    `asset_tag_id` BIGINT COMMENT 'Primary key for the asset_tag association',
    `asset_id` BIGINT COMMENT 'Foreign key linking to the content asset being tagged. Each record associates this asset with one metadata tag.',
    `metadata_tag_id` BIGINT COMMENT 'Foreign key linking to the controlled vocabulary metadata tag applied to the asset.',
    `confidence_score` DECIMAL(18,2) COMMENT 'AI/ML confidence score (0.0000–1.0000) for this specific asset-tag pairing when tagging_method is AUTO_AI. Null for manually applied tags. Belongs to the association because the same tag applied to different assets will have different confidence scores from the model.',
    `is_primary_tag` BOOLEAN COMMENT 'Indicates whether this tag is designated as a primary/featured tag for the asset within its taxonomy category (e.g., the primary sport tag, the primary athlete tag). Supports ranked display and personalization prioritization. Belongs to the asset-tag relationship, not to either entity alone.',
    `review_status` STRING COMMENT 'Editorial review status of this specific tag application. Relevant when metadata_tag.review_required is true. Tracks whether a human editor has approved or rejected this tag for this asset. Belongs to the association event, not to the tag master record.',
    `tagged_by_user` STRING COMMENT 'Username or system identifier of the editorial user or automated process that applied this tag to this asset. Belongs to the tagging event, not to the asset or the tag. Used for editorial accountability, workflow auditing, and quality review.',
    `tagged_timestamp` TIMESTAMP COMMENT 'Date and time when this specific metadata tag was applied to this specific asset. Belongs to the tagging event, not to the asset or the tag independently. Used for audit trails, editorial workflow tracking, and tag freshness analysis.',
    `tagging_method` STRING COMMENT 'Method by which this tag was applied to the asset. Distinguishes human editorial tagging from AI auto-tagging, bulk ingest tagging, or rules-engine-driven tagging. Critical for quality assurance workflows and confidence-based filtering.',
    CONSTRAINT pk_asset_tag PRIMARY KEY(`asset_tag_id`)
) COMMENT 'This association product represents the tagging event between a content asset and a controlled vocabulary metadata tag in the Dalet Galaxy DAM. It captures the operational record of each tag application — whether performed by an editorial user, an AI auto-tagging pipeline, or a bulk ingest process. Each record links one asset to one metadata tag and carries attributes that exist only in the context of that specific tagging action: when it was applied, by whom or what system, via which method, and with what AI confidence. This is the authoritative source of truth for all asset-tag associations across OTT, broadcast, and digital platforms.. Existence Justification: In DAM (Digital Asset Management) operations, a single content asset (e.g., a match highlight video) is tagged with MULTIPLE controlled vocabulary metadata tags simultaneously — sport, league, team, athlete, event type, mood, content rating, etc. Conversely, a single metadata tag (e.g., Premier League) is applied to thousands of assets. This is the canonical M:N relationship in every DAM system: content tagging. The business actively manages these tag applications through editorial workflows, AI auto-tagging pipelines, and compliance review processes — each tagging event carries its own operational data (who tagged it, when, how, with what confidence).';

